/**
 * scenarios.js — 100 scénarios officiels de l'épreuve "questions dans la voiture".
 * Source : DSR/BRPCE (jan. 2018). Numérotation : 2 derniers chiffres du compteur.
 *
 * Chaque objet contient :
 *   id       : "01"–"99" + "00"
 *   type1    : "VI" (vérification intérieure) | "VE" (vérification extérieure)
 *   q1/a1    : question et réponse officielle de vérification
 *   explain1 : explication pédagogique (pourquoi c'est important)
 *   photo1   : nom de fichier image dans /public/photos/ (optionnel)
 *   q2/a2    : question et réponse QSER (sécurité routière)
 *   explain2 : explication QSER
 *   q3/a3    : question et réponse premiers secours
 *   explain3 : explication premiers secours
 */

export const SCENARIOS = [
  {"id": "00","type1": "VE","q1": "Montrez où se trouve la jauge d'huile moteur.","a1": "Ouvrir le capot et montrer la jauge (tige avec repères MIN/MAX), moteur froid.","explain1": "Vérifier à froid sur terrain plat. Niveau bas = risque de grippage moteur en quelques minutes.","photo1": "jauge-huile.jpg","q2": "Quel est le risque d'une consommation excessive d'huile moteur lors d'un long trajet ?","a2": "Risque de surchauffe et de grippage moteur en quelques minutes, perte totale du moteur.","explain2": "L'huile lubrifie et refroidit les pièces en mouvement. Sans elle, frottement intense et destruction rapide.","q3": "Comment positionner une victime en position latérale de sécurité (PLS) ?","a3": "Personne sur le dos, jambe fléchie, bras en appui, tête basculée en arrière (dégager les voies aériennes).","explain3": "La PLS prévient l'asphyxie par régurgitation et maintient les voies aériennes ouvertes chez une victime inconsciente."},
  {"id": "01","type1": "VI","q1": "Montrez la commande de réglage de hauteur des feux.","a1": "Dispositif situé en général à gauche du volant.","explain1": "Ce correcteur de site adapte l'angle des feux à la charge. Plus la voiture est chargée à l'arrière, plus les feux pointent vers le haut — risque d'éblouir les autres.","photo1": "correcteur-feux.jpg","q2": "Pourquoi doit-on régler la hauteur des feux ?","a2": "Pour ne pas éblouir les autres usagers.","explain2": "Un mauvais réglage réduit la visibilité des conducteurs en face. C'est aussi un point vérifié au contrôle technique.","q3": "Comment et pourquoi protéger une zone de danger en cas d'accident de la route ?","a3": "En délimitant clairement et largement la zone de danger de façon visible pour protéger les victimes et éviter un sur-accident.","explain3": "Le sur-accident est fréquent et mortel. Baliser large et tôt est la priorité AVANT les premiers secours."},
  {"id": "02","type1": "VE","q1": "Montrez où s'effectue le remplissage du produit lave-glace.","a1": "Ouvrir le capot et montrer le bocal lave-glace (bouchon bleu en général).","explain1": "Ne jamais confondre avec le liquide de refroidissement. Mettre du lave-glace dans le mauvais réservoir peut endommager le moteur.","photo1": "bocal-lave-glace.jpg","q2": "Pourquoi est-il préférable d'utiliser un liquide lave-glace spécial en hiver ?","a2": "Pour éviter le gel du liquide.","explain2": "Un liquide gelé bloque les gicleurs ou fait éclater le bocal. Utiliser un liquide antigel adapté à -20°C min.","q3": "Quels comportements adopter en cas de diffusion du signal d'alerte du SAIP ?","a3": "Se mettre en sécurité. S'informer via les médias et sites des autorités. Respecter les consignes des autorités.","explain3": "SAIP = danger imminent (catastrophe, attentat…). L'appli SAIP envoie aussi des alertes push sur smartphone."},
  {"id": "03","type1": "VI","q1": "Mettez le rétroviseur intérieur en position « nuit ».","a1": "Basculer la languette sous le rétroviseur, ou indiquer le système automatique si équipé.","explain1": "La position nuit incline le miroir pour renvoyer les phares arrière vers le bas. Sans ça, éblouissement direct à 90 km/h = 125 m 'à l'aveugle'.","photo1": "retroviseur-nuit.jpg","q2": "Quel est l'intérêt de la position nuit ?","a2": "Ne pas être ébloui par les feux du véhicule suiveur.","explain2": "L'éblouissement provoque 2 à 5 secondes de cécité temporaire. À 90 km/h = 125 m sans visibilité.","q3": "Comment est composé le signal d'alerte du SAIP diffusé par les sirènes ?","a3": "Deux codes : Signal National d'Alerte (SNA) = variation sur 3 cycles successifs. Signal de fin d'alerte = signal continu.","explain3": "Signal modulé (montée/descente) = danger en cours. Signal continu = fin d'alerte. À connaître pour ne pas paniquer inutilement."},
  {"id": "04","type1": "VE","q1": "Contrôlez l'état du flanc sur l'un des pneumatiques.","a1": "Vérification visuelle du flanc : en bon état, sans coupure, boursouflure ni déformation. Toute anomalie doit être signalée.","explain1": "Le flanc est la partie la plus fragile du pneu (chocs de trottoir). Une boursouflure = risque d'éclatement imminent.","photo1": "flanc-pneumatique.jpg","q2": "Citez un endroit où l'on peut trouver les pressions préconisées pour les pneumatiques.","a2": "Sur une plaque sur une portière, dans la notice d'utilisation, ou au niveau de la trappe à carburant.","explain2": "La pression varie selon la charge et l'essieu. Toujours vérifier à froid. Sous-gonflage = surchauffe + usure anormale.","q3": "Sur autoroute, comment indiquer avec précision les lieux d'un accident depuis un téléphone portable ?","a3": "En indiquant le numéro de l'autoroute, le sens de circulation et le point kilométrique.","explain3": "Les bornes d'appel orange (tous les 2 km) transmettent automatiquement la position — idéales après une panne.","requiredCount2": 1},
  {"id": "05","type1": "VI","q1": "Faites fonctionner les essuie-glaces avants du véhicule sur la position la plus rapide.","a1": "Actionner le levier des essuie-glaces sur la colonne de direction et le placer sur la position la plus rapide.","explain1": "Les positions vont d'intermittent à rapide. En fortes pluies, la vitesse max est indispensable pour maintenir la visibilité.","photo1": "levier-essuie-glaces.jpg","q2": "Comment détecter l'usure des essuie-glaces en circulation ?","a2": "En cas de pluie, lorsqu'ils laissent des traces sur le pare-brise.","explain2": "Stries ou zones non essuyées = caoutchouc durci ou abîmé. À changer avant l'hiver, tous les 1-2 ans.","q3": "Comment vérifier la respiration d'une victime ?","a3": "Regarder si le ventre et la poitrine se soulèvent, et sentir de l'air à l'expiration.","explain3": "Technique LVA : Voir, Écouter, Sentir pendant 10 secondes. Pas de respiration → commencer la RCP immédiatement."},
  {"id": "06","type1": "VE","q1": "Vérifiez l'état et la propreté des plaques d'immatriculation.","a1": "Vérification des plaques avant et arrière : propres, lisibles et en bon état. Toute anomalie doit être signalée.","explain1": "Une plaque illisible constitue une infraction. Elle doit être visible de nuit grâce à l'éclairage de plaque.","photo1": "plaque-immatriculation.jpg","q2": "Quelles sont les précautions à prendre en cas d'installation d'un porte-vélo ?","a2": "La plaque d'immatriculation et les feux doivent rester visibles.","explain2": "Un porte-vélo masquant la plaque ou les feux est illégal. Il faut fixer une plaque et des feux déportés sur le porte-vélo.","q3": "Qu'est-ce qu'une perte de connaissance ?","a3": "C'est lorsque la victime ne répond pas et ne réagit pas, mais respire.","explain3": "Perte de connaissance (respire) → PLS. Arrêt cardiaque (ne respire plus) → RCP. Confondre les deux peut être fatal."},
  {"id": "07","type1": "VI","q1": "Vérifiez la présence du gilet de haute visibilité.","a1": "Indiquer où se trouve le gilet dans le véhicule, sans obligation de le sortir.","explain1": "Le gilet doit être accessible depuis l'intérieur (pas dans le coffre) pour le mettre AVANT de sortir du véhicule.","photo1": "gilet-haute-visibilite.jpg","q2": "En cas de panne ou d'accident, quel autre accessoire de sécurité est obligatoire ?","a2": "Le triangle de pré-signalisation.","explain2": "Ces deux équipements sont obligatoires depuis 2008. Sur autoroute, le triangle ne doit PAS être placé (trop dangereux).","q3": "Si un dégagement d'urgence de la victime est nécessaire, où doit-elle être déplacée ?","a3": "Dans un endroit suffisamment éloigné du danger et de ses conséquences.","explain3": "Le dégagement n'est justifié que si le danger est RÉEL, IMMÉDIAT et NON CONTRÔLABLE. Sinon, ne pas bouger la victime."},
  {"id": "08","type1": "VE","q1": "Montrez où s'effectue le contrôle du niveau du liquide de frein.","a1": "Ouvrir le capot et montrer le bocal de liquide de frein (petit réservoir transparent avec repères MIN/MAX).","explain1": "Niveau trop bas = fuite ou usure des plaquettes. Un circuit vide en roulant = pédale qui 'tombe dans le plancher'.","photo1": "bocal-liquide-frein.jpg","q2": "Quelle est la conséquence d'un niveau insuffisant du liquide de frein ?","a2": "Une perte d'efficacité du freinage.","explain2": "Si le niveau baisse à cause d'une fuite, le freinage peut devenir quasi nul en quelques appuis. Urgence absolue.","q3": "En cas de panne ou d'accident, quel équipement de sécurité doit être porté avant de quitter le véhicule ?","a3": "Le gilet de haute visibilité.","explain3": "La majorité des piétons tués sur route la nuit l'étaient faute de visibilité. Le gilet multiplie la distance de détection par 3 à 4."},
  {"id": "09","type1": "VI","q1": "Vérifiez la présence du certificat d'immatriculation du véhicule (ou carte grise).","a1": "Montrer le certificat d'immatriculation. La photocopie est acceptée.","explain1": "Depuis 2017, le certificat peut être présenté en version numérique (app ANTS). La photocopie est acceptée depuis 2013.","photo1": "carte-grise.jpg","q2": "Quels sont les deux autres documents obligatoires à présenter en cas de contrôle par les forces de l'ordre ?","a2": "L'attestation d'assurance et le permis de conduire.","explain2": "3 documents : carte grise + attestation assurance + permis. Sans assurance = 3 750€ d'amende + suspension possible.","q3": "Pourquoi l'alerte auprès des services de secours doit-elle être rapide et précise ?","a3": "Pour permettre aux services de secours d'apporter les moyens adaptés aux victimes dans le délai le plus court.","explain3": "Pour un arrêt cardiaque, chaque minute sans défibrillation = -10% de chances de survie. La précision détermine les moyens envoyés.","requiredCount2": 2},
  {"id": "10","type1": "VE","q1": "Contrôlez l'état de tous les balais d'essuie-glace du véhicule.","a1": "Inspecter visuellement les balais : en bon état, sans craquelure ni déformation du caoutchouc.","explain1": "Soulever le bras et faire glisser le caoutchouc entre les doigts. Un balai usé laisse des zones non essuyées = danger.","photo1": "balais-essuie-glace.jpg","q2": "Quel est le risque de circuler avec des balais d'essuie-glace défectueux ?","a2": "Une mauvaise visibilité en cas d'intempéries.","explain2": "Par pluie forte, des balais défectueux réduisent la visibilité à quelques mètres. Pénalisé au contrôle technique.","q3": "Quels sont les numéros d'urgence à composer ?","a3": "18 (pompiers), 15 (SAMU), 112 (numéro européen valable dans toute l'UE).","explain3": "Le 112 fonctionne sans crédit, sans code PIN, depuis n'importe quel réseau mobile en Europe. À retenir absolument."},
  {"id": "11","type1": "VI","q1": "Montrez l'indicateur de niveau de carburant.","a1": "Montrer la jauge de carburant sur le tableau de bord (aiguille entre E et F, ou affichage numérique).","explain1": "La flèche à côté du symbole pompe indique de quel côté est le bouchon du réservoir — utile à la station-service !","photo1": "jauge-carburant.jpg","q2": "Quelles sont les précautions à prendre lors du remplissage du réservoir ?","a2": "Arrêter le moteur, ne pas fumer, ne pas téléphoner.","explain2": "Les vapeurs d'essence sont très inflammables. Une étincelle de téléphone ou décharge statique peut déclencher un incendie.","q3": "Quels comportements adopter en présence d'une victime qui ne répond pas et ne réagit pas, mais respire ?","a3": "La placer en Position Latérale de Sécurité (PLS), alerter les secours, surveiller la respiration jusqu'à leur arrivée.","explain3": "La PLS évite que la victime s'étouffe avec sa langue ou ses vomissements. Face légèrement vers le bas, bouche vers le sol."},
  {"id": "12","type1": "VE","q1": "Montrez où s'effectue le remplissage du liquide de refroidissement.","a1": "Ouvrir le capot et montrer le bocal de liquide de refroidissement (transparent avec repères MIN/MAX).","explain1": "Ne JAMAIS ouvrir ce bocal moteur chaud : la pression projetterait du liquide bouillant. Attendre que le moteur soit froid.","photo1": "bocal-refroidissement.jpg","q2": "Quel est le danger si l'on complète le niveau du liquide lorsque le moteur est chaud ?","a2": "Un risque de brûlure.","explain2": "Le liquide est à plus de 90°C sous pression. L'ouverture du bouchon provoque une décompression violente sur le visage et les mains.","q3": "Comment arrêter une hémorragie ?","a3": "En appuyant fortement sur l'endroit qui saigne avec les doigts ou la paume de la main, en mettant un tissu propre sur la plaie.","explain3": "Compression directe = seul geste efficace immédiatement. Maintenir sans relâcher. Ne pas retirer le tissu s'il se gorge : en ajouter un par-dessus."},
  {"id": "13","type1": "VI","q1": "Actionnez le dégivrage de la lunette arrière et montrez le voyant ou le repère correspondant.","a1": "Appuyer sur le bouton de dégivrage lunette arrière (symbole rectangle + lignes horizontales) et montrer le voyant allumé.","explain1": "Des filaments conducteurs dans la vitre chauffent pour éliminer le givre. La lunette doit être entièrement dégagée avant de rouler.","photo1": "degivrage-lunette.jpg","q2": "Quelle peut être la conséquence d'une panne de dégivrage de la lunette arrière ?","a2": "Une insuffisance ou une absence de visibilité vers l'arrière.","explain2": "En hiver sans dégivrage, le rétroviseur intérieur est inutilisable. Risque accru lors des manœuvres et changements de voie.","q3": "Hors autoroute, en cas de panne ou d'accident, où doit être placé le triangle de pré-signalisation ?","a3": "À environ 30 m de la panne ou de l'accident, ou avant un virage, ou avant un sommet de côte.","explain3": "Sur autoroute, ne JAMAIS placer le triangle — trop dangereux. 30 m = environ 10 grandes enjambées. Toujours gilet AVANT de sortir."},
  {"id": "14","type1": "VE","q1": "Contrôlez l'état, la propreté et le fonctionnement de tous les clignotants côté trottoir.","a1": "Vérification des clignotants avant, latéral et arrière côté trottoir : propres, en bon état et fonctionnant. Toute anomalie signalée.","explain1": "Pour vérifier seul : activer les clignotants et faire le tour. Ou observer le reflet dans une vitrine.","photo1": "clignotants.jpg","q2": "Quelle est la signification d'un clignotement plus rapide que d'habitude ?","a2": "Non-fonctionnement de l'une des ampoules.","explain2": "Le système accélère le clignotement pour alerter le conducteur. À corriger rapidement : les autres usagers ne voient plus les intentions.","q3": "Quelles sont les conditions pour réaliser le dégagement d'urgence d'une victime ?","a3": "La victime doit être visible, facile à atteindre, rien ne doit gêner son dégagement, et on doit être sûr de pouvoir le réaliser.","explain3": "Le dégagement ne se justifie QUE si le danger est réel, immédiat et non contrôlable (ex : incendie). Sinon, ne pas bouger la victime."},
  {"id": "15","type1": "VI","q1": "Montrez le voyant d'alerte signalant une pression insuffisante d'huile dans le moteur.","a1": "Montrer le voyant en forme de lampe à huile (icône rouge) sur le tableau de bord.","explain1": "Ce voyant rouge est critique. S'il s'allume en roulant → arrêter IMMÉDIATEMENT le moteur. Continuer = destruction moteur en quelques minutes.","photo1": "voyant-huile.jpg","q2": "Quelles sont les conditions à respecter pour contrôler le niveau d'huile ?","a2": "Moteur froid et sur un terrain plat.","explain2": "Moteur chaud = huile dilatée, niveau faussé. En pente, l'huile se répartit inégalement dans le carter = lecture erronée.","q3": "Quelles sont les trois informations à transmettre aux services de secours ?","a3": "Le numéro de téléphone depuis lequel l'appel est émis, la nature du problème, et la localisation la plus précise possible.","explain3": "Mémo : QUI (numéro), QUOI (nature), OÙ (localisation). Ces 3 infos permettent d'envoyer les bons moyens au bon endroit.","requiredCount3": 3},
  {"id": "16","type1": "VE","q1": "Contrôlez l'état, la propreté et le fonctionnement du ou des feux de brouillard arrière.","a1": "Vérification des feux de brouillard arrière : propres, en bon état et fonctionnant. Toute anomalie signalée.","explain1": "Ces feux rouges très lumineux améliorent la visibilité arrière dans le brouillard. En dehors, ils éblouissent les autres.","photo1": "feux-brouillard-arriere.jpg","q2": "Dans quels cas utilise-t-on les feux de brouillard arrière ?","a2": "Par temps de brouillard et neige.","explain2": "Uniquement quand la visibilité est inférieure à 50 m. Les utiliser par beau temps = risque d'éblouissement + amende.","q3": "Par quels moyens doit être réalisée l'alerte des secours ?","a3": "À l'aide d'un téléphone portable ou, à défaut, d'un téléphone fixe ou d'une borne d'appel d'urgence.","explain3": "Les bornes d'appel sur autoroute (toutes les 2 km) sont gratuites, localisées automatiquement et prioritaires sur le réseau."},
  {"id": "17","type1": "VI","q1": "Vérifiez la présence de l'éthylotest.","a1": "Montrer l'éthylotest présent dans le véhicule (obligatoire, généralement dans la boîte à gants).","explain1": "Obligatoire depuis 2012. L'éthylotest chimique ou électronique permet de contrôler son propre taux d'alcoolémie avant de conduire.","photo1": "ethylotest.jpg","q2": "A partir de quel taux d'alcoolémie, en période de permis probatoire, est-on en infraction ?","a2": "0,2 g/l — c'est-à-dire 0 verre, car dès le 1er verre ce seuil peut être dépassé.","explain2": "Pour les permis probatoires : seuil 0,2 g/l (quasi-zéro). Pour les permis classiques : 0,5 g/l. Un seul verre = risque réel.","q3": "Quel comportement doit-on adopter en présence d'une victime en arrêt cardiaque ?","a3": "ALERTER : alerter immédiatement les secours. MASSER : réanimation cardio-pulmonaire. DÉFIBRILLER : utiliser un DAE si possible.","explain3": "Mémo AMD (Alerter, Masser, Défibriller). Chaque minute sans RCP = -10% de survie. Ne pas attendre les secours pour commencer."},
  {"id": "18","type1": "VE","q1": "Contrôlez l'état, la propreté et le fonctionnement des feux de détresse à l'avant et à l'arrière.","a1": "Vérification des feux de détresse : propres, en bon état et fonctionnant. Toute anomalie signalée.","explain1": "Les feux de détresse (tous les clignotants simultanément) signalent un danger ou une immobilisation soudaine.","photo1": "feux-detresse.jpg","q2": "Dans quels cas doit-on utiliser les feux de détresse ?","a2": "En cas de panne, d'accident ou de ralentissement important.","explain2": "Utile aussi sur autoroute pour avertir les véhicules suivants d'un bouchon soudain. Ne pas oublier d'éteindre après.","q3": "Dans quel cas peut-on positionner une victime en Position Latérale de Sécurité (PLS) ?","a3": "Si la victime ne répond pas, ne réagit pas et respire.","explain3": "La PLS = inconsciente MAIS respire. Si elle ne respire plus → RCP. Si elle est consciente → ne pas la déplacer (blessures possibles)."},
  {"id": "19","type1": "VI","q1": "Montrez la commande de réglage du volant.","a1": "Montrer l'emplacement de la commande de réglage du volant (déverrouillage/réglage, généralement levier sous le volant).","explain1": "Bien régler le volant = posture correcte, accès aux commandes, visibilité du tableau de bord, et airbag efficace en cas de choc.","photo1": "reglage-volant.jpg","q2": "Pourquoi est-il important de bien régler son volant ? Citez deux exemples.","a2": "Confort de conduite, accessibilité aux commandes, visibilité du tableau de bord, efficacité des airbags.","explain2": "Un volant trop proche ou trop loin crée fatigue et réflexes plus lents. L'airbag est conçu pour une distance volant-conducteur précise.","q3": "Dans quelle situation peut-on déplacer une victime ?","a3": "En présence d'un danger réel, immédiat et non contrôlable. Le déplacement doit rester exceptionnel.","explain3": "Déplacer une victime avec fracture cervicale non détectée peut provoquer une tétraplégie. Ne bouger que si danger vital immédiat.","requiredCount2": 2},
  {"id": "20","type1": "VE","q1": "Contrôlez l'état, la propreté et le fonctionnement des feux de route.","a1": "Vérification des feux de route : propres, en bon état et fonctionnant. Toute anomalie signalée.","explain1": "Les feux de route éclairent jusqu'à 100 m (vs 50 m pour les feux de croisement). Obligatoire de les passer en croisement.","photo1": "feux-route.jpg","q2": "Citez un cas d'utilisation de l'appel lumineux.","a2": "Pour avertir de son approche, en cas de danger, ou à la place de l'avertisseur sonore.","explain2": "L'appel lumineux est plus discret et socialement accepté que le klaxon. En agglomération, le klaxon est interdit sauf danger immédiat.","q3": "En cas de panne ou d'accident, quel équipement de sécurité doit être porté avant de quitter le véhicule ?","a3": "Le gilet de haute visibilité.","explain3": "Porter le gilet AVANT de sortir du véhicule, même sur le bord d'une route tranquille. Le réflexe peut sauver la vie.","requiredCount2": 1},
  {"id": "21","type1": "VI","q1": "Positionnez la commande pour diriger l'air vers le pare-brise.","a1": "Orienter le sélecteur de ventilation vers l'icône pare-brise (dégivrage/désembuage).","explain1": "La position 'pare-brise' concentre l'air chaud sur la vitre pour désembuer rapidement. Astuce : combiner avec la clim pour un air sec.","photo1": "ventilation-pare-brise.jpg","q2": "Citez deux éléments complémentaires permettant un désembuage efficace.","a2": "La commande de vitesse de ventilation, la commande d'air chaud, et la climatisation.","explain2": "La clim assèche l'air et accélère drastiquement le désembuage même en hiver. Contre-intuitif mais très efficace.","q3": "Quel est l'objectif du Signal d'Alerte et d'Information des Populations (SAIP) ?","a3": "Avertir la population d'un danger imminent ou qu'un événement grave est en train de se produire.","explain3": "Le SAIP remplace les vieilles sirènes de la Guerre froide. Il peut aussi envoyer des notifications push via l'application dédiée.","requiredCount2": 2},
  {"id": "22","type1": "VE","q1": "Comment vérifier le niveau de liquide de refroidissement ?","a1": "Ouvrir le capot moteur froid, observer le niveau entre MIN et MAX sur le vase d'expansion.","explain1": "Vérifier à moteur froid pour une lecture précise. Un niveau bas risque de surchauffe moteur.","photo1": "vase-expansion.jpg","q2": "Quel est le danger d'un moteur qui surchauffe pendant la conduite ?","a2": "Risque de grippage moteur, de perte de puissance, d'arrêt complet et d'incendie moteur.","explain2": "L'eau refroidit le moteur. Sans refroidissement, les pièces se dilatent et se bloquent instantanément.","q3": "Quels sont les numéros d'urgence à connaître en France ?","a3": "15 (SAMU), 17 (Police), 18 (Pompiers), 112 (urgence UE), 114 (malentendants).","explain3": "Ces numéros permettent de joindre immédiatement les secours adaptés 24h/24. Le 112 fonctionne depuis tout téléphone."},
  {"id": "23","type1": "VI","q1": "Comment vérifier l'état des ceintures de sécurité ?","a1": "Tirer sur chaque ceinture avec force, vérifier qu'elle ne s'enroule pas et que le clic d'encliquetage est audible.","explain1": "Une ceinture usée ou desserrée ne protège pas. Elle doit être correctement encliquetée à chaque utilisation.","photo1": "ceinture-securite.jpg","q2": "Pourquoi le port de la ceinture réduit-il les blessures graves en cas d'accident ?","a2": "Elle retient le corps contre la déformation du véhicule, répartit les chocs sur les zones résistantes (poitrine, bassin).","explain2": "Sans ceinture, le corps continue à 90 km/h lors d'un freinage d'urgence. La ceinture absorbe cette énergie progressivement.","q3": "Comment arrêter une hémorragie externe ?","a3": "Comprimer la plaie avec un pansement propre ou tissu, maintenir la compression 5-10 minutes sans vérifier.","explain3": "La compression continue arrête le saignement en favorisant la coagulation. Ôter le pansement risque de reprendre l'hémorragie."},
  {"id": "24","type1": "VE","q1": "Où se trouvent les fusibles et comment vérifier un fusible défaillant ?","a1": "Localiser la boîte à fusibles (tableau de bord ou moteur), inspecter le filament (doit être intact).","explain1": "Un fusible grillé protège le circuit électrique. Remplacer par un fusible de même ampérage (indiqué sur le fusible).","photo1": "boite-fusibles.jpg","q2": "Quel risque court-on en utilisant un fusible de puissance supérieure à celle d'origine ?","a2": "Risque d'incendie électrique, de surchauffe du câblage, de court-circuit non contrôlé.","explain2": "Le fusible est un élément de sécurité qui coupe le circuit avant surcharge. Le forcer compromet toute protection.","q3": "Reconnaître les signes d'un malaise cardiaque chez une victime.","a3": "Douleur thoracique, dyspnée (essoufflement), pâleur, sueurs froides, malaise soudain.","explain3": "Ces signes demandent appel immédiat au 15 et mise au repos. L'inactivité prolongée augmente le risque d'arrêt cardiaque."},
  {"id": "25","type1": "VI","q1": "Vérifier le fonctionnement du klaxon du véhicule.","a1": "Appuyer sur le centre du volant (ou bouton dédié) : le klaxon doit émettre un son clair et distinct.","explain1": "Le klaxon alerte les autres usagers en cas de danger. Un dysfonctionnement réduit la sécurité en ville et sur route.","photo1": "klaxon-volant.jpg","q2": "Dans quelles situations doit-on actionner le klaxon de façon préventive ?","a2": "Avant de dépasser, en approche d'un virage aveugle, à la sortie de garage, en zone à faible visibilité.","explain2": "Le klaxon prévient les usagers cachés (vélos, piétons). Son utilisation précoce limite les collisions évitables.","q3": "Comment réaliser une RCP sur un enfant (1-8 ans) ?","a3": "30 compressions avec 1-2 doigts (5 cm de profondeur, 100-120/min) puis 2 insufflations. Même ratio que l'adulte.","explain3": "Un enfant a une cage thoracique plus fine. Les compressions superficielles ne pompent pas le cœur efficacement."},
  {"id": "26","type1": "VE","q1": "Contrôlez l'état, la propreté et le fonctionnement des feux de croisement.","a1": "Vérification des feux de croisement : propres, en bon état et fonctionnant. Toute anomalie signalée.","explain1": "Les feux de croisement éclairent 50 m devant et s'inclinent vers le bas pour ne pas éblouir. À utiliser dès la tombée de la nuit.","photo1": "feux-croisement.jpg","q2": "Quelles sont les conséquences d'un mauvais réglage de ces feux ?","a2": "Une mauvaise vision vers l'avant et un risque d'éblouissement des autres usagers.","explain2": "Des feux trop hauts = éblouissement systématique. Trop bas = visibilité insuffisante. Réglage à revoir après un chargement lourd.","q3": "Dans quelle situation peut-on déplacer une victime ?","a3": "En présence d'un danger réel, immédiat et non contrôlable. Le déplacement doit rester exceptionnel.","explain3": "Un mouvement brusque peut transformer une fracture vertébrale en tétraplégie. Ne déplacer que si danger vital immédiat."},
  {"id": "27","type1": "VI","q1": "Comment vérifier le fonctionnement du voyant ABS du tableau de bord ?","a1": "À la mise en contact (avant démarrage), le voyant ABS s'allume 2-3 secondes puis s'éteint. S'il reste allumé, ABS défaillant.","explain1": "L'ABS prévient le blocage des roues au freinage. Un ABS défaillant multiplie les risques de dérapage sur sol mouillé.","photo1": "voyant-abs.jpg","q2": "Quel est le comportement du véhicule lors d'un freinage d'urgence sans ABS sur sol mouillé ?","a2": "Les roues se bloquent, le véhicule chasse (perte d'adhérence), le conducteur perd la maîtrise directionnelle.","explain2": "L'ABS maintient une adhérence partielle en pulsant les freins. Sans ABS, le blocage = glissade inévitable sur sol glissant.","q3": "Quelles sont les étapes de la RCP chez un nourrisson (< 1 an) ?","a3": "30 compressions avec 2 doigts (3 cm de profondeur) alternées avec 2 insufflations dans le nez-bouche.","explain3": "Les mains du nourrisson sont minuscules. Les doigts suffisent à comprimer l'os sternal sans fracture."},
  {"id": "28","type1": "VE","q1": "Vérifier l'état et la tension de la courroie d'accessoires (serpentine).","a1": "Ouvrir le capot, inspecter la courroie (pas d'usure visible, de fissure) ; appuyer : déflexion max 10 mm.","explain1": "La courroie entraîne alternateur, compresseur, pompe direction. Une rupture = perte charge batterie et direction assistée.","photo1": "courroie-accessoires.jpg","q2": "Quels sont les symptômes d'une courroie usée ou tendue incorrectement ?","a2": "Bruit strident au démarrage, perte de direction assistée, batterie déchargée, absence de climatisation.","explain2": "Une courroie glisse (usure) ou casse (rupture) → perte des accessoires. Ces perte créent un danger immédiat.","q3": "Comment traiter une brûlure superficielle (1er degré) ?","a3": "Passer sous eau froide 10-15 min, appliquer une compresse propre, surélever la zone. Pas de glaçon direct.","explain3": "L'eau froide arrête la chaleur et réduit le gonflement. Glaçon direct = risque de brûlure par froid."},
  {"id": "29","type1": "VI","q1": "Vérifier le voyant de température du moteur sur le tableau de bord.","a1": "À la mise en contact, le voyant clignote puis s'éteint au bout de 2-3 secondes après le démarrage.","explain1": "Un voyant allumé signale une surchauffe. Arrêter immédiatement et vérifier liquide refroidissement et ventilation.","photo1": "voyant-temperature.jpg","q2": "Quel risque court-on en continuant à rouler avec le voyant de température allumé ?","a2": "Surchauffe progressive du moteur, risque de grippage, d'incendie moteur, destruction totale du moteur.","explain2": "Le moteur ne peut fonctionner sans refroidissement. Continuer = destruction garantie en quelques kilomètres.","q3": "Comment identifier un choc anaphylactique et le traiter ?","a3": "Signes : éruption cutanée, gonflement facial, difficultés respiratoires, perte de conscience. Injecter auto-injecteur si présent, appeler 15.","explain3": "L'anaphylaxie est une réaction allergique grave. L'adrénaline ralentit la progression. Les secours doivent intervenir vite."},
  {"id": "30","type1": "VE","q1": "Où se trouvent et comment contrôler les feux de position avant ?","a1": "Ouvrir le capot, localiser les petites ampoules blanches côté avant. Vérifier qu'elles s'allument en position veille.","explain1": "Les feux de position signalent la présence la nuit. Une absence rend le véhicule invisible de loin (risque collision).","photo1": "feux-position.jpg","q2": "Quel est le risque d'un feu de position avant hors service la nuit ?","a2": "Diminution de la visibilité du véhicule par les autres usagers, augmentation des collisions de nuit.","explain2": "Les feux position visibilité passive. Autre conducteur ne voit que le feu stop au freinage (trop tard pour réagir).","q3": "Comment reconnaître et traiter un étouffement par corps étranger ?","a3": "Signes : toux, respiration difficulté, impossibilité de parler. Effectuer claques dorsales puis compressions abdominales.","explain3": "Corps étranger bloque les voies respiratoires. Claques dorsales + compressions abdominales dégagent l'obstruction rapidement."},
  {"id": "31","type1": "VI","q1": "Vérifier le fonctionnement du voyant de charge batterie du tableau de bord.","a1": "À la mise en contact avant démarrage, le voyant s'illumine. Au démarrage moteur, il s'éteint en 2-3 secondes.","explain1": "Voyant allumé = alternateur défaillant, batterie se décharge. Risque de panne totale sur la route.","photo1": "voyant-batterie.jpg","q2": "Quelles sont les conséquences d'une batterie faible en roulant de nuit ?","a2": "Phares affaiblis (mauvaise visibilité), ralentissement des essuie-glaces, risque stalling du moteur.","explain2": "La batterie alimente tout l'électrique. Faible = tous les systèmes ralentissent. Perte de sécurité progressive.","q3": "Comment contrôler les saignements de nez (épistaxis) chez une victime ?","a3": "Asseoir la victime, pencher la tête légèrement en avant (pas en arrière), comprimer la narine pendant 10 min.","explain3": "Pencher en avant évite l'avalement de sang (fausse route). La compression directe arrête l'hémorragie par coagulation."},
  {"id": "32","type1": "VE","q1": "Comment vérifier l'état des feux stop (feux rouges arrière) ?","a1": "Demander à quelqu'un d'appuyer sur le frein pendant que vous observez les deux feux stop rouges.","explain1": "Les feux stop avertissent des freinage. Une absence = risque de collision arrière par non-visibilité du freinage.","photo1": "feux-stop.jpg","q2": "Quel danger représente un feu stop défaillant sur autoroute ?","a2": "Le véhicule derrière ne voit pas le freinage et percute le véhicule, causant un accident en chaîne.","explain2": "Sur autoroute, 130 km/h. 2 secondes sans voir le freinage = distance de 72 mètres parcourue sans réaction.","q3": "Comment traiter une victime en état de choc ?","a3": "Allonger à plat, jambes surélevées (15 cm), couvrir de couverture, ne rien faire boire/manger, appeler secours.","explain3": "Le choc réduit la circulation sanguine. Surélever les jambes aide la perfusion cérébrale. L'immobilité prévient l'aggravation."},
  {"id": "33","type1": "VI","q1": "Comment vérifier le réglage du siège conducteur ?","a1": "S'asseoir, vérifier que les pieds atteignent les pédales, que les bras sont légèrement fléchis au volant.","explain1": "Un mauvais réglage fatigue et réduit le contrôle du véhicule. Chaque conducteur doit régler avant de démarrer.","photo1": "siege-conducteur.jpg","q2": "Quel est l'impact d'un siège mal réglé sur la sécurité en cas de coup du lapin lors d'une collision arrière ?","a2": "L'appui-tête n'amortit pas correctement, risque de blessure cervicale grave (entorse, fracture).","explain2": "L'appui-tête doit être à la hauteur du crâne. Si trop bas, le cou bascule en arrière sans protection.","q3": "Quand et comment utiliser un Défibrillateur Automatisé Externe (DAE) ?","a3": "Dès que disponible sur victime inconsciente sans réaction et sans respiration. Placer les électrodes, appuyer sur ON, suivre les instructions.","explain3": "Le DAE détecte la fibrillation ventriculaire et envoie un choc électrique pour réinitialiser le cœur. Chaque minute compte."},
  {"id": "34","type1": "VE","q1": "Comment vérifier les feux de recul (blancs) du véhicule ?","a1": "Passer en marche arrière avec phares allumés et observer les deux feux blancs à l'arrière.","explain1": "Les feux recul éclairent et signalent les mouvements arrière. Absence = risque d'accident arrière, heurt de piétons.","photo1": "feux-recul.jpg","q2": "Quel danger y a-t-il à faire marche arrière sans vérifier les feux de recul ?","a2": "Piétons ou cyclistes ne voient pas le recul et risquent d'être percutés, surtout de nuit ou par visibilité réduite.","explain2": "Les feux recul donnent une seconde couche de sécurité. Surélévé à l'arrière, ils alertent les usagers derrière.","q3": "Comment reconnaître une fracture et la traiter sur le terrain ?","a3": "Signes : douleur vive, déformation, gonflement, impotence. Immobiliser le membre, appliquer glaçon + compression, rehausser.","explain3": "Immobilisation prévient les lésions supplémentaires et réduit la douleur. Glaçon + compression réduisent l'œdème."},
  {"id": "35","type1": "VI","q1": "Vérifier le fonctionnement de la commande des phares (codes et route).","a1": "Placer la main sur la commande gauche du volant, vérifier codes (position basse) et route (position haute).","explain1": "Les codes garantissent la visibilité sans éblouir les autres. Le passage en route doit être court et pertinent.","photo1": "commande-phares.jpg","q2": "Pourquoi le passage intempestif aux phares de route peut-il causer un accident ?","a2": "L'éblouissement du conducteur opposé réduit sa vision à zéro pendant 2-5 secondes, risque de collision de front.","explain2": "Éblouissement = adaptation rétinienne brisée. Conducteur aveugle. Un véhicule à 90 km/h parcourt 125 m en 5 secondes.","q3": "Comment différencier un arrêt cardiaque d'une simple syncope et intervenir ?","a3": "Syncope : respiration bruyante; arrêt cardiaque : absence totale respiration. Réaliser RCP même en cas de doute.","explain3": "Mieux vaut une RCP inutile qu'une RCP manquante. Chaque minute sans RCP = 10% de survie perdue."},
  {"id": "36","type1": "VE","q1": "Comment vérifier les phares de plaque (éclairage plaque arrière) ?","a1": "Allumer les phares et observer la plaque arrière : elle doit être complètement éclairée et lisible de loin.","explain1": "La plaque illuminée permet identification du véhicule la nuit. Absence = amende + risque d'accident camouflé.","photo1": "eclairage-plaque.jpg","q2": "Quel risque de sécurité routière y a-t-il avec une plaque d'immatriculation mal éclairée ?","a2": "Les forces de l'ordre ne peuvent identifier le véhicule de nuit, gêne la surveillance des infractions, camouflage d'accident.","explain2": "Plaque non lisible = impossible d'identifier le fautif. Risque d'impunité et d'incitation à la non-responsabilité.","q3": "Comment traiter une noyade et réanimer une victime aquatique ?","a3": "Sortir de l'eau, dégager voies aériennes, si perte conscience : mettre en PLS, appeler secours. RCP si pas respiration.","explain3": "L'eau dans les voies aériennes asphyxie rapidement. PLS drains l'eau des voies aériennes. RCP ranime le cœur."},
  {"id": "37","type1": "VI","q1": "Vérifier le fonctionnement du voyant d'appui-tête manquant ou absent.","a1": "Observer l'appui-tête du siège conducteur (doit être présent et à hauteur du crâne, non à la nuque).","explain1": "L'appui-tête prévient les blessures cervicales en cas de coup du lapin. Absence = obligation légale non respectée.","photo1": "appuie-tete.jpg","q2": "Quel est le mécanisme de la blessure du coup du lapin et le rôle de l'appui-tête ?","a2": "Collision arrière accélère le corps en avant, mais la tête bascule en arrière (inertie), étire les muscles cervicaux. L'appui-tête amortit.","explain2": "Force rapide sur le cou = étirement des muscles. Appui-tête arrête la bascule en avant du crâne, limite l'étirement.","q3": "Comment aider une victime en intoxication par gaz carbonique (CO) ou monoxyde carbone ?","a3": "Sortir immédiatement de la zone contaminée (fenêtres ouvertes), mettre la victime au repos/PLS, appeler 15.","explain3": "CO se lie à hémoglobine plus vite que O2. Sortir rapidement permet la réoxygénation. Symptômes peuvent arriver tardivement."},
  {"id": "38","type1": "VE","q1": "Comment vérifier le clignotant côté conducteur (avant et arrière) ?","a1": "Placer la clé en mode veille, actionner la commande gauche (clignotant à gauche), observer feux clignoter rythme régulier.","explain1": "Les clignotants signalent les changements direction. Absence ou dysfonctionnement = impossible de communiquer intentions.","photo1": "clignotant-conducteur.jpg","q2": "Quel risque représente un clignotant hors service lors d'un changement de voie sur l'autoroute ?","a2": "Autres conducteurs ne savent pas votre intention, risque de collision latérale, choc, accident en chaîne.","explain2": "Clignotant = avertisseur passif. Absence = usagers ignorent mouvement. À 130 km/h, d'autres ne peuvent pas réagir.","q3": "Comment évaluer et traiter une convulsion chez une victime consciente ?","a3": "Laisser convulser sans la retenir, écarter les objets dangereux, mettre en PLS après, rester auprès, appeler secours.","explain3": "Immobiliser convulsion risque de blessure. PLS après évite asphyxie. Secours cherchent la cause (épilepsie, trauma)."},
  {"id": "39","type1": "VI","q1": "Vérifier le fonctionnement du dégivrage avant (pare-brise et lunette).","a1": "Mettre le contact, actionner le bouton de dégivrage, vérifier souffle chaud et buée disparition sur le pare-brise.","explain1": "Le dégivrage élimine le givre/condensation. Pare-brise gelé = visibilité nulle, danger immédiat, impossible rouler légalement.","photo1": "degivrage-avant.jpg","q2": "Pourquoi démarrer sans dégivrer complètement le pare-brise augmente le risque d'accident ?","a2": "Visibilité réduite, impossible de voir obstacles/piétons, impossibilité réaction d'urgence, risque collision frontale.","explain2": "Visibilité = base de la réaction. Sans vision claire, conducteur aveugle. Accident inévitable en cas obstacle.","q3": "Comment reconnaître et traiter une victime d'électrocution (choc électrique) ?","a3": "Éteindre l'électricité (disjoncteur) sans toucher, ne pas déplacer, vérifier réaction, appeler secours, RCP si besoin.","explain3": "Contact électrique = risque arrêt cardiaque. Couper source évite nouvelle électrocution. RCP relance le cœur."},
  {"id": "40","type1": "VE","q1": "Comment vérifier l'état des rétroviseurs extérieurs (droite et gauche) ?","a1": "Observer chaque rétroviseur, vérifier surface sans fissure, angle de vision dégagé, position réglable du siège.","explain1": "Rétroviseurs offrent visibilité arrière/flanc. Cassés ou mal réglés = angles morts dangereux, impossibilité manœuvre sûre.","photo1": "retroviseurs-exterieurs.jpg","q2": "Quel est le risque d'un rétroviseur mal réglé lors d'un changement de voie sur autoroute ?","a2": "Angles morts non couverts, impossible voir véhicule dans la voie visée, collision latérale inévitable lors du changement.","explain2": "Rétroviseur mal réglé = zone cachée. À 130 km/h, un véhicule se rapproche de 36 m en 1 seconde. Impossible réaction.","q3": "Comment identifier et traiter un malaise hypoglycémique chez une victime consciente ?","a3": "Signes : tremblements, sueurs, agitation, confusion. Donner du sucre rapide (bonbon, jus), asseoir, surveiller, appeler si perte conscience.","explain3": "Hypoglycémie = cerveau affamé. Sucre rapide = récupération rapide. Manque action = perte conscience, coma possible."},
  {"id": "41","type1": "VI","q1": "Vérifier le fonctionnement de la climatisation/ventilation intérieure.","a1": "Mettre le contact, actionner climatisation, vérifier air froid sort des grilles, réglage température/vitesse.","explain1": "Climatisation maintient la vigilance (fatigue réduite). Dysfonctionnement = fatigue, perte de concentration, danger accident.","photo1": "climatisation.jpg","q2": "Comment la fatigue due à une mauvaise climatisation affecte-t-elle la sécurité routière ?","a2": "Somnolence, ralentissement des réflexes, endormissement au volant, temps de réaction augmenté, accident inévitable.","explain2": "Température élevée = somnolence rapide (hyperthermie). Conducteur s'endort, perte de contrôle, collision imminente.","q3": "Comment traiter une personne enceinte victime d'un malaise ou d'une chute ?","a3": "Allonger légèrement sur flanc gauche, jambes surélevées, surveiller respiration, appeler secours (risque accouchement prématuré).","explain3": "Surélévation légère sur flanc gauche améliore retour veineux et circulation fœtale. Sécurité mère ET enfant."},
  {"id": "42","type1": "VE","q1": "Comment vérifier l'état de la carrosserie et des portières du véhicule ?","a1": "Inspecter visiblement portières (sans rouille étendue), vérifier fermeture solide, absence de jeu excessif.","explain1": "Carrosserie rouillée ou portière mal fermée = intégrité structurelle compromise. Risque déboîtement porte en cas collision.","photo1": "carrosserie-portieres.jpg","q2": "Quel est le risque d'une portière mal fermée ou rouillée lors d'une manœuvre brusque ou collision ?","a2": "Porte s'ouvre intempestivement, passager éjecté, loss de la structure de protection du châssis en cas crash.","explain2": "Porte = première ligne défense en latéral. Mal fermée = protection nulle. Passager risque éjection (mort quasi certaine).","q3": "Comment reconnaître et traiter une victime d'empoisonnement alimentaire ou intoxication digestive ?","a3": "Signes : nausées, vomissements, douleurs abdominales, diarrhée. Hydratation progressive (eau par petites quantités), appeler secours si grave.","explain3": "Intoxication = déhydratation rapide. Eau lentement reconstruit l'hydratation. Secours si signes graves (fièvre, sang)."},
  {"id": "43","type1": "VI","q1": "Vérifier le fonctionnement du frein à main (ou frein de parking) du véhicule.","a1": "Actionner le frein à main, sentir résistance mécanique, relâcher, vérifier sans bruit anormal.","explain1": "Le frein à main maintient le véhicule à l'arrêt. Défaillance = véhicule roule au parking, risque collision, perte contrôle.","photo1": "frein-main.jpg","q2": "Pourquoi un frein à main défaillant augmente-t-il le risque d'accident sur un parking en pente ?","a2": "Véhicule roule lentement mais progressivement, percute obstacle/autre véhicule, impossible arrêt sans moteur.","explain2": "Frein à main = dernier barrage immobilité. Défaillance = perte cette ligne. Pente = accélération progressive inévitable.","q3": "Comment reconnaître une personne en détresse psychologique ou suicidaire lors d'une intervention secours ?","a3": "Signes : agitation, agressivité, propos incohérents, fixité du regard, automutilation. Rester calme, écouter, appeler secours.","explain3": "Détresse psycho = risque nuisance à soi. Écoute empathique + secours spécialisés (psys, pompiers) réduisent escalade."},
  {"id": "44","type1": "VE","q1": "Comment vérifier le fonctionnement de l'antenne radio/télévision du véhicule ?","a1": "Ouvrir les portes pour observer antenne (ne pas cassée), tester réception radio en allumant poste.","explain1": "Antenne cassée = réception radio mauvaise. Conducteur distrait en cherchant fréquence, attention route réduite, danger.","photo1": "antenne.jpg","q2": "Quel est le risque d'une mauvaise réception radio en continu pour la sécurité routière ?","a2": "Conducteur cherche fréquence, distraction manuelle, attention réduite route, temps réaction augmenté, accident inévitable.","explain2": "Distraction = temps réaction augmenté 0.5 → 2 secondes. À 90 km/h = 50 mètres parcourus sans réaction. Collision certaine.","q3": "Comment identifier une victime inconsciente mais respirant et évaluer l'urgence respiratoire ?","a3": "Dégager voies aériennes, écouter respiration (6-20 cycles/min normal), placer en PLS, monitoring respiratoire continu.","explain3": "Inconscience + respiration = stabilité relative. Respiration irrégulière/ralentie = déclin progressif. Monitoring permet détection."},
  {"id": "45","type1": "VI","q1": "Comment vérifier la commande des clignotants (levier à gauche du volant) ?","a1": "Actionner vers le haut (clignotant droit) et vers le bas (clignotant gauche), observer les feux s'allumer et s'éteindre régulièrement.","explain1": "Commande défaillante = impossible signaler changement direction. Autres conducteurs ignorent intentions, accidents latéraux.","photo1": "commande-clignotants.jpg","q2": "Pourquoi la commande des clignotants défaillante est-elle particulièrement dangereuse lors d'un dépassement sur route ?","a2": "Impossible avertir véhicule derrière, risque collision frontale lors du redémarrage en file ou collision latérale.","explain2": "Dépassement = manipulation dangereuse. Clignotant = seul avertissement. Absence = conducteur derrière ignore danger.","q3": "Comment différencier les étapes de la RCP et adapter à l'âge de la victime (enfant vs adulte) ?","a3": "Adulte : 30 compressions (5 cm) + 2 insufflations. Enfant : même ratio mais profondeur 4-5 cm, force adaptée poids.","explain3": "Compression efficace = 1/3 profondeur thoracique. Enfant = thorax plus petit = moins de profondeur. Ratio compressions/insufflations universel."},
  {"id": "46","type1": "VE","q1": "Vérifiez la propreté des feux de position avant.","a1": "Inspection visuelle des feux de position avant : propres, en bon état et fonctionnant.","explain1": "Les feux de position signalent la présence du véhicule. Un feu HS = contravention et risque de collision nocturne.","photo1": "feux-position-avant.jpg","q2": "Dans quelles conditions les feux de position sont-ils obligatoires ?","a2": "La nuit et lorsque la visibilité est insuffisante (pluie, brouillard, tunnel).","explain2": "Les feux de position seuls suffisent en stationnement éclairé. En circulation la nuit, les feux de croisement sont obligatoires.","q3": "Comment réaliser la manœuvre de Heimlich sur un adulte qui s'étouffe ?","a3": "Se placer derrière la victime, mettre le poing entre nombril et sternum, l'autre main par-dessus, et faire des compressions abdominales vers l'intérieur et le haut.","explain3": "La compression abdominale crée une surpression pulmonaire qui expulse le corps étranger."},
  {"id": "47","type1": "VI","q1": "De quelle couleur est le voyant qui indique au conducteur que le feu de brouillard arrière est allumé ?","a1": "Le voyant est de couleur orange/ambre (représente un feu arrière avec lignes).","explain1": "Orange = information importante à surveiller. Rouge = anomalie grave ou danger. Mémoriser cette convention pour tous les voyants.","photo1": "voyant-brouillard.jpg","q2": "Quelle est la différence entre un voyant orange et un voyant rouge ?","a2": "Rouge : anomalie de fonctionnement ou danger. Orange : élément important à surveiller.","explain2": "Rouge allumé en roulant = arrêter rapidement. Orange = surveiller et intervenir bientôt. Vert/bleu = information neutre.","q3": "Qu'est-ce qu'un arrêt cardiaque ?","a3": "Le cœur ne fonctionne plus ou fonctionne d'une façon anarchique (fibrillation).","explain3": "Fibrillation = le cœur tremble sans pomper le sang. Seul le défibrillateur peut resynchroniser les contractions. C'est pour ça que les DAE sont dans les lieux publics."},
  {"id": "48","type1": "VE","q1": "Vérifiez l'état des joints de portières.","a1": "Inspection visuelle : joints sans fissures, déchirures ni déformations. Aucune infiltration d'eau ou d'air.","explain1": "Les joints assurent l'étanchéité. Des joints usés causent infiltrations d'eau et augmentent le bruit.","photo1": "joints-portires-etat.jpg","q2": "Quels risques représentent des joints de portières défectueux ?","a2": "Infiltrations d'eau, moisissures, augmentation du bruit, corrosion interne du véhicule.","explain2": "L'humidité favorise la rouille des éléments métalliques et détériore l'électronique embarquée.","q3": "Comment traiter une hémorragie grave avec un garrot ?","a3": "Placer le garrot 10-15 cm au-dessus de la blessure, bien serrer jusqu'à arrêt du saignement, marquer l'heure sur le garrot, surélever le membre.","explain3": "Le garrot comprime l'artère et arrête le saignement. L'heure permet aux médecins de surveiller la durée (risque de nécrose au-delà de 2h)."},
  {"id": "49","type1": "VI","q1": "Vérifiez le voyant ESP (contrôle de stabilité) au démarrage.","a1": "Le voyant doit s'allumer brièvement au démarrage, puis s'éteindre. Un voyant permanent = dysfonctionnement.","explain1": "L'ESP aide le conducteur en freinant les roues qui patinent. Un ESP défaillant réduit la stabilité en virage ou glissance.","photo1": "voyant-esp-vsc.jpg","q2": "Quel rôle joue l'ESP dans la sécurité routière en cas de glissance ?","a2": "L'ESP détecte la perte d'adhérence et freine les roues individuellement pour corriger la trajectoire et maintenir la stabilité.","explain2": "En conditions mouillées, l'ESP prévient les dérapages et aide le conducteur à conserver le contrôle sans surbraquage.","q3": "Comment traiter une brûlure chimique sur la peau ?","a3": "Rincer immédiatement et abondamment à l'eau tiède pendant 10-15 minutes, retirer vêtements contaminés (sauf s'ils collent), couvrir sans appuyer, appeler le SAMU.","explain3": "L'eau neutralise chimiquement et refroidit la brûlure. Un rinçage rapide limite la profondeur et la gravité."},
  {"id": "50","type1": "VE","q1": "Vérifiez le fonctionnement des lève-vitres électriques.","a1": "Actionnez les commandes : vitres montent/descendent régulièrement sans à-coups. Pas de blocage ni de bruit anormal.","explain1": "Les vitres assurent la visibilité et ventilation du véhicule. Une vitre qui ne fonctionne pas nuit à la sécurité.","photo1": "leve-vitres-electriques.jpg","q2": "Pourquoi est-il important que les lève-vitres fonctionnent correctement ?","a2": "Une vitre coincée réduit la visibilité, empêche la ventilation et gêne l'évacuation en cas d'urgence ou d'accident.","explain2": "La vitre avant réduit le bruit ambiant. L'impossibilité de l'ouvrir crée un problème de sécurité et de confort.","q3": "Comment traiter une intoxication alimentaire ?","a3": "Maintenir la victime au repos, lui donner à boire régulièrement de petites quantités d'eau tiède, surveiller signes graves. Appeler le SAMU si vomissements sévères.","explain3": "Le repos et l'hydratation permettent à l'organisme de lutter contre la toxine. Les médecins interviennent si complications graves."},
  {"id": "51","type1": "VI","q1": "Vérifiez le voyant airbag sur le tableau de bord.","a1": "Le voyant doit s'allumer brièvement au démarrage, puis s'éteindre. Voyant permanent ou clignotant = panne.","explain1": "Les airbags sont essentiels à la protection en cas de choc frontal. Un voyant permanent = système défaillant, véhicule à ne pas utiliser.","photo1": "voyant-airbag.jpg","q2": "Quel rôle jouent les airbags dans la sécurité passagers en cas d'accident ?","a2": "Ils se déploient en millisecondes lors d'un choc pour former un coussin d'air qui amortit l'impact et prévient les blessures à la tête et au thorax.","explain2": "Associés à la ceinture, les airbags réduisent de 30-50% le risque de blessure grave en collision frontale.","q3": "Comment traiter une noyade chez une victime inconsciente ?","a3": "Placer la victime en position latérale de sécurité, libérer les voies aériennes, vérifier la respiration. RCP si apnée.","explain3": "La position latérale prévient l'aspiration. La RCP rétablit la circulation sanguine et oxygénée."},
  {"id": "52","type1": "VE","q1": "Vérifiez l'état du pare-brise (impacts et fissures).","a1": "Inspection visuelle : pas de fissure en ligne, pas d'impact > 3 cm en zone de visibilité directe du conducteur.","explain1": "Le pare-brise assure la visibilité et maintient structurellement le toit en cas de tonneau. Une fissure compromet ces deux fonctions.","photo1": "pare-brise-impacts.jpg","q2": "Pourquoi un pare-brise endommagé est-il dangereux en cas d'accident ?","a2": "Il ne peut pas supporter la déformation du toit, amplifiant les blessures. Il réduit aussi la visibilité et nuit au déploiement de l'airbag passager.","explain2": "En tonneau, le pare-brise intègre renfort structurel. Un pare-brise faible augmente les risques de décapitation.","q3": "Comment traiter un malaise diabétique chez une victime consciente ?","a3": "Lui donner du sucre rapide (3-5 morceaux ou jus) et de l'eau. Si malaise persiste, manger léger. Appeler le médecin si crise sévère.","explain3": "Le sucre lève rapidement l'hypoglycémie. L'alimentation régulière prévient les rechutes."},
  {"id": "53","type1": "VI","q1": "Vérifiez la commande du régulateur de vitesse.","a1": "Actionnez les boutons (augmenter, diminuer, annuler) : la vitesse doit se maintenir ou revenir à la normale.","explain1": "Le régulateur aide le conducteur à maintenir une vitesse constante. Un dysfonctionnement peut causer une accélération accidentelle.","photo1": "commande-regulateur-vitesse.jpg","q2": "Comment le régulateur de vitesse contribue-t-il à la sécurité routière ?","a2": "Il réduit la fatigue du conducteur sur autoroute et aide à respecter les limites de vitesse. Il diminue les variations inutiles.","explain2": "Un conducteur moins fatigué est plus attentif. La vitesse stable réduit la consommation et les dépassements non contrôlés.","q3": "Comment traiter une fracture ouverte avec plaie saignante ?","a3": "Arrêter le saignement par compression douce, immobiliser le membre, surélever si possible, appliquer pansement stérile, appeler le SAMU.","explain3": "L'immobilisation prévient l'aggravation. Le garrot s'ajoute si saignement massif."},
  {"id": "54","type1": "VE","q1": "Vérifiez la présence du triangle de pré-signalisation.","a1": "Montrer la présence du triangle de pré-signalisation dans le véhicule (généralement dans le coffre).","explain1": "Le triangle doit être dans le coffre, accessible rapidement. Le modèle homologué affiche un 'E' dans un cercle sur la boîte.","photo1": "triangle-presignalisation.jpg","q2": "Utilise-t-on le triangle de pré-signalisation sur autoroute ?","a2": "Non.","explain2": "Sur autoroute, il est trop dangereux d'aller placer le triangle. Rester dans le véhicule ou derrière les glissières, utiliser les feux de détresse.","q3": "Quel comportement doit-on adopter en présence d'une victime en arrêt cardiaque ?","a3": "ALERTER les secours immédiatement. MASSER : réanimation cardio-pulmonaire. DÉFIBRILLER avec un DAE si possible.","explain3": "La chaîne de survie : alerte précoce + RCP immédiate + défibrillation rapide. Chaque maillon compte — la RCP seule double les chances."},
  {"id": "55","type1": "VI","q1": "Vérifiez la commande du limiteur de vitesse.","a1": "Actionnez les boutons (augmenter, diminuer, annuler) : la limite doit s'établir ou s'annuler selon l'ordre.","explain1": "Le limiteur empêche le dépassement accidentel d'une vitesse programmée. Un dysfonctionnement peut entraîner une accélération involontaire.","photo1": "commande-limiteur-vitesse.jpg","q2": "Quel est le rôle du limiteur de vitesse dans le respect de la sécurité routière ?","a2": "Il empêche le dépassement involontaire d'une limite de vitesse, notamment en zones dangereuses. Il protège contre les excès accidentels.","explain2": "En coupant l'accélération, le limiteur prévient les dépassements même si le conducteur appuie à fond.","q3": "Comment traiter une morsure d'animal (chien, chat, animal sauvage) ?","a3": "Laver la plaie à l'eau et au savon, appliquer un antiseptique, couvrir d'un pansement. Consulter un médecin pour vérifier la vaccination (rage notamment).","explain3": "La plaie peut être infectée. La rage nécessite un traitement d'urgence si l'animal est inconnu."},
  {"id": "56","type1": "VE","q1": "Vérifiez la propreté et l'état des optiques (feux).","a1": "Inspection visuelle : tous les feux doivent être propres (sans givre, saleté) et fonctionnels. Pas de craquelure du verre.","explain1": "Les optiques sales réduisent la visibilité et l'avertissement aux autres usagers. C'est une infraction et un danger routier.","photo1": "optiques-feux-proprete.jpg","q2": "Comment l'état des optiques affecte-t-il la sécurité en circulation nocturne ?","a2": "Des feux sales ou HS réduisent l'éclairage et rendent le véhicule moins visible. Cela augmente le risque de collision la nuit.","explain2": "Une optique encrassée perd 50% de son efficacité lumineuse. L'absence de feu supprime l'avertissement aux autres automobilistes.","q3": "Comment traiter un étouffement chez un nourrisson (< 1 an) ?","a3": "Placer le nourrisson face vers le bas sur l'avant-bras, faire 5 tapes entre les omoplates. Puis retourner et faire 5 compressions thoraciques avec 2 doigts.","explain3": "Les tapes utilisent la gravité et la percussion. Les compressions créent une surpression thoracique complémentaire."},
  {"id": "57","type1": "VI","q1": "Vérifiez le fonctionnement du klaxon (son clair et fort).","a1": "Appuyez sur la commande : un son clair et fort doit retentir. Pas de son faible, cassé ou absent.","explain1": "Le klaxon avertit les autres usagers d'une présence ou d'un danger. Un klaxon défaillant réduit la communication entre véhicules.","photo1": "klaxon-son-test.jpg","q2": "Pourquoi le klaxon est-il un élément crucial de communication routière ?","a2": "Il permet de signaler immédiatement sa présence en cas de danger immédiat (freinage d'urgence, obstacle soudain, piéton).","explain2": "Le klaxon force l'attention. Un conducteur inattentif ne verra pas les gestes, seul le klaxon fonctionne.","q3": "Comment traiter un accident électrique avec contact ligne électrique ?","a3": "Ne pas toucher la victime si contact ! Couper l'électricité à la source ou demander aux services. Puis déplacer délicatement. RCP si nécessaire.","explain3": "Le courant peut traverser les secouristes. L'isolement de la source est prioritaire. La RCP traite les arrêts cardio-respiratoires fréquents."},
  {"id": "58","type1": "VE","q1": "Vérifiez le niveau et l'état de la boîte de vitesses.","a1": "Sur moteur froid, vérifier le niveau entre min et max. Vérifier aussi la couleur (rouge clair) : ne doit pas être noire ou brûlée.","explain1": "Une boîte asséchée ou avec huile dégradée souffre. Cela cause des à-coups et peut mener à un blocage du véhicule.","photo1": "niveau-boite-vitesses.jpg","q2": "Quel impact un niveau insuffisant de boîte de vitesses a-t-il sur la sécurité ?","a2": "La boîte peut glisser, donner des à-coups à l'accélération, ou bloquer lors d'une manœuvre d'urgence, immobilisant le véhicule.","explain2": "Un glissement de boîte lors d'un dépassement crée une perte de contrôle dangereuse.","q3": "Comment traiter une crise d'épilepsie ?","a3": "Écarter les meubles/objets, placer la victime en position latérale de sécurité, surveiller la respiration. Ne rien forcer dans la bouche. Appeler le SAMU.","explain3": "La position latérale prévient l'étouffement. La surveillance permet de détecter un arrêt respiratoire."},
  {"id": "59","type1": "VI","q1": "Vérifiez le réglage du siège passager.","a1": "Testez les commandes d'ajustement : tous les mouvements doivent être fluides et le siège doit se bloquer.","explain1": "Un siège mal réglé peut glisser en freinage. Un dossier mal bloqué peut basculer en freinage d'urgence.","photo1": "reglage-siege-passager.jpg","q2": "Pourquoi le bon réglage du siège passager est-il important en cas de freinage d'urgence ?","a2": "Un siège bien bloqué maintient le passager en place, réduisant le risque de blessure et facilitant le déploiement de l'airbag.","explain2": "Un siège qui glisse désaligne le passager par rapport à l'airbag, réduisant l'efficacité de la protection.","q3": "Comment traiter un accouchement d'urgence sur la route ?","a3": "Appeler le SAMU immédiatement. Installer la mère allongée/semi-assise. Laisser la nature faire. Recevoir le bébé dans un linge propre. Clamper le cordon si kit disponible.","explain3": "L'accouchement rapide favorise l'expulsion. Le bébé respire seul après la naissance. L'arrivée du SAMU sécurise la phase placentaire."},
  {"id": "60","type1": "VE","q1": "Vérifiez le toit ouvrant (fonctionnement et étanchéité).","a1": "Actionnez la commande : ouverture/fermeture fluide, pas de bruit anormal. Fermer complètement et vérifier qu'il ne s'infiltre pas d'eau.","explain1": "Un toit qui fuit cause de l'humidité, de la rouille et des dommages électroniques. Un moteur grippé rend le toit coincé.","photo1": "toit-ouvrant-test.jpg","q2": "Quels risques représente un toit ouvrant défaillant ou qui fuit ?","a2": "Infiltration d'eau, moisissures, court-circuits électriques, augmentation de la rouille. Un toit coincé réduit aussi la ventilation.","explain2": "L'eau stagnante crée un environnement humide favorisant les dégâts matériels et les risques électriques.","q3": "Comment traiter une hypothermie légère (victime consciente) ?","a3": "Mettre la victime au chaud progressivement (enlever vêtements mouillés, couvertures), la laisser au repos, lui donner boissons chaudes. Surveiller signes de choc.","explain3": "Le réchauffement progressif prévient les chocs thermiques. Les boissons chaudes augmentent la température interne."},
  {"id": "61","type1": "VI","q1": "Vérifiez le miroir de courtoisie et son éclairage.","a1": "Ouvrir le cache : il doit s'ouvrir/fermer aisément. Vérifier que l'éclairage fonctionne.","explain1": "Le miroir de courtoisie aide les passagers. Son éclairage facilite l'accès de nuit.","photo1": "miroir-courtoisie-eclairage.jpg","q2": "En quoi le miroir de courtoisie contribue-t-il au confort et à la sécurité ?","a2": "Il permet aux passagers d'ajuster leur apparence, ce qui évite des distractions du conducteur. L'éclairage facilite la vision de nuit.","explain2": "Un passager qui se maquille en utilisant le miroir ne demande pas au conducteur de s'arrêter, maintenant sa concentration.","q3": "Comment traiter une brûlure superficielle (1er degré) ?","a3": "Refroidir immédiatement sous l'eau tiède pendant 10-15 minutes. Appliquer une crème apaisante. Couvrir d'un pansement large. Prendre du paracétamol contre la douleur.","explain3": "Le refroidissement ralentit la pénétration de la chaleur. L'hydratation prévient le dessèchement. Guérison en 1-2 semaines sans cicatrice."},
  {"id": "62","type1": "VE","q1": "Vérifiez l'état des amortisseurs (visuel).","a1": "Inspection visuelle : amortisseurs sans fuite (tige brillante mais sans dégoulinement). Pas de rouille perforante. Ressorts non cassés.","explain1": "Des amortisseurs usés augmentent la distance de freinage, réduisent la tenue de route et augmentent l'usure des pneus.","photo1": "amortisseurs-visuel-etat.jpg","q2": "Comment des amortisseurs usés affectent-ils le contrôle du véhicule en freinage ou en virage ?","a2": "Ils augmentent le roulis, réduisent la stabilité, allongent la distance de freinage et augmentent le risque de glisse en virage.","explain2": "L'amortisseur absorbe les oscillations. Sans lui, le pneu perd contact avec la route, réduisant l'adhérence.","q3": "Comment traiter une RCP (réanimation cardio-pulmonaire) sur un nourrisson (0-12 mois) ?","a3": "Vérifier conscience et respiration (< 10 sec). Compressions : 2 doigts, 100-120/min, 4-5 cm de profondeur. Insufflations : couvrir nez+bouche. Ratio 30:2.","explain3": "La RCP nourrisson s'adapte à la taille fragile. Les compressions légères ne cassent pas les côtes. Le ratio 30:2 oxygène le cerveau."},
  {"id": "63","type1": "VI","q1": "Vérifiez le fonctionnement des serrures centralisées.","a1": "Appuyez sur le bouton de déverrouillage ou utilisez la télécommande : toutes les portes doivent se verrouiller/déverrouiller simultanément.","explain1": "Les serrures centralisées assurent la sécurité en confinement. Un dysfonctionnement peut laisser le véhicule ouvert ou piéger les passagers.","photo1": "serrures-centralisees-test.jpg","q2": "Pourquoi les serrures centralisées sont-elles essentielles à la sécurité ?","a2": "Elles empêchent les intrusions et les ouvertures accidentelles (enfant). Elles permettent aussi le confinement en cas de danger.","explain2": "Un enfant ne peut pas ouvrir les portes si les serrures enfant sont activées. Le verrouillage centralisé prévient les vols.","q3": "Comment traiter une RCP chez un adulte ?","a3": "Vérifier conscience et respiration (< 10 sec). Compressions : 2 mains au sternum, 100-120/min, 5-6 cm de profondeur. Insufflations : 1 seconde par 30 compressions.","explain3": "Les compressions restaurent la circulation. Les insufflations oxygènent les poumons. Le ratio 30:2 optimise la récupération cérébrale."},
  {"id": "64","type1": "VE","q1": "Vérifiez l'état du bouchon de réservoir.","a1": "Démonter le bouchon : pas de fissure, joint intact, mécanisme de verrouillage fonctionnel. Carburant sans odeur anormale.","explain1": "Un bouchon défaillant permet l'évaporation du carburant et augmente les émissions polluantes.","photo1": "bouchon-reservoir-carburant.jpg","q2": "Pourquoi l'intégrité du bouchon de réservoir est-elle importante pour la sécurité et l'environnement ?","a2": "Un bouchon mal serré augmente les émissions polluantes. Une fissure peut causer une fuite en virage ou accident.","explain2": "L'essence qui fuit augmente le risque de glissade sur la chaussée. Les vapeurs augmentent la pollution et créent un feu en cas de fuite importante.","q3": "Comment traiter une hémorragie interne (victime consciente) ?","a3": "Allonger la victime, surélever les jambes (si possible sans douleur), surveiller signes de choc (pâleur, sueurs, pouls faible), garder au chaud, faire boire petites gorgées d'eau.","explain3": "La surélévation des jambes favorise la circulation vers le cerveau. Le repos limite les saignements internes."},
  {"id": "65","type1": "VI","q1": "Vérifiez la commande des feux de route et croisement.","a1": "Actionnez les commandes : phares doivent basculer entre croisement (bas) et route (haut). Vérifier que les 2 phares fonctionnent.","explain1": "Les feux de croisement éclairent sans éblouir les opposés. Les feux de route éclairent loin mais éblouissent. Mal utiliser nuit à la sécurité.","photo1": "commande-feux-route-croisement.jpg","q2": "Quel est l'impact d'une mauvaise utilisation des feux de route sur la sécurité routière ?","a2": "Éblouir les automobilistes opposés diminue leur visibilité et crée un risque de collision frontale. C'est une infraction et une source d'accident grave.","explain2": "Un conducteur ébloui perd la vision de la route 2-3 secondes. En cas de virage, il peut percuter un obstacle.","q3": "Comment traiter une hémorragie nasale (saignement de nez) ?","a3": "Asseoir la victime, la pencher légèrement en avant, comprimer la narine avec un tissu. Laisser s'arrêter (5-10 min). Ne pas moucher.","explain3": "La compression directe arrête le saignement. Pencher en avant évite la déglutition de sang."},
  {"id": "66","type1": "VE","q1": "Vérifiez l'état des rétroviseurs extérieurs.","a1": "Inspection visuelle : pas de fissure, verre bien attaché. Réglage : couvrir l'arrière et les angles morts (vue latérale du sol).","explain1": "Les rétroviseurs extérieurs élargissent le champ de vision. Un rétroviseur cassé réduit la visibilité arrière et latérale.","photo1": "retroviseurs-exterieurs-etat.jpg","q2": "Comment des rétroviseurs mal réglés augmentent les risques d'accident ?","a2": "Ils réduisent la visibilité arrière et latérale, augmentant l'angle mort. Le conducteur peut ne pas voir un véhicule qui dépasse.","explain2": "L'angle mort à droite d'un poids lourd est énorme. Les rétroviseurs mal réglés créent des zones invisibles similaires, surtout pour les changements de voie.","q3": "Comment traiter une luxation (articulation qui a bougé) ?","a3": "Immobiliser immédiatement le membre dans sa position actuelle sans essayer de remettre en place. Appliquer de la glace. Appeler le SAMU.","explain3": "Toute tentative de réduction peut blesser les nerfs/vaisseaux. L'immobilisation prévient l'aggravation. La réduction médicale est obligatoire."},
  {"id": "67","type1": "VI","q1": "Vérifiez l'indicateur de pression des pneus (TPMS).","a1": "Vérifier que le voyant TPMS s'allume brièvement au démarrage. Aucune alerte persistante pendant la conduite.","explain1": "Le TPMS alerte en cas de sous-gonflage ou crevaison. Une alerte persistante signale un problème.","photo1": "indicateur-tpms-pneus.jpg","q2": "Pourquoi le contrôle de pression des pneus est-il crucial pour la sécurité ?","a2": "Une sous-gonflage augmente la distance de freinage, réduit la maniabilité et crée un risque d'éclatement. Une sur-gonflage réduit le contact au sol.","explain2": "La pression correcte optimise l'adhérence et réduit la consommation. Une mauvaise pression crée l'usure rapide.","q3": "Comment traiter une chute grave avec suspicion de trauma crânien ou spinal ?","a3": "Ne pas déplacer sauf danger immédiat. Maintenir la tête immobile, appliquer compresses stériles si saignement léger. Surveiller conscience et respiration. Appeler le SAMU.","explain3": "Le déplacement peut aggraver une fracture vertébrale causant une paraplégie. L'immobilisation prévient les complications neurologiques graves."},
  {"id": "68","type1": "VE","q1": "Vérifiez le fonctionnement du lève-vitres arrière.","a1": "Actionnez la commande arrière : vitres doivent monter/descendre régulièrement. Tester aussi la coupure enfant si présente.","explain1": "Les vitres arrière assurent la visibilité arrière et la ventilation. Une vitre collée crée une mauvaise aération.","photo1": "leve-vitres-arriere-test.jpg","q2": "Pourquoi la visibilité arrière correcte est-elle importante pour la sécurité ?","a2": "Elle permet de détecter les véhicules qui arrivent par l'arrière, les piétons, les obstacles. Une visibilité réduite augmente le risque de collision arrière.","explain2": "Un conducteur ne voyant pas derrière risque une collision en roulant lentement ou en marche arrière.","q3": "Comment traiter une syncope (malaise/évanouissement) ?","a3": "Allonger la victime, surélever légèrement les jambes, desserrer les vêtements, passer de l'eau froide sur le visage. Si perte conscience : position latérale. Appeler le SAMU.","explain3": "La surélévation des jambes augmente le flux sanguin vers le cerveau. L'eau froide stimule. La position latérale prévient l'étouffement."},
  {"id": "69","type1": "VI","q1": "Vérifiez la commande de l'essuie-glace et lave-glace.","a1": "Actionnez la commande d'essuie-glace : balais doivent balayer régulièrement sans à-coups. Actionnez le lave-glace : du liquide doit asperger.","explain1": "L'essuie-glace maintient la visibilité par temps de pluie. Un essuie-glace défaillant augmente le risque d'accident. Le lave-glace enlève la saleté.","photo1": "essuie-glace-lave-glace.jpg","q2": "Comment les essuie-glaces contribuent-ils à la sécurité en conduite par mauvaise visibilité ?","a2": "Ils maintiennent le pare-brise propre et dégagé de la pluie, permettant au conducteur de voir. Un essuie-glace qui grince nuit à la visibilité.","explain2": "Un conducteur qui ne voit pas bien tend à ralentir et être moins attentif aux dangers latéraux.","q3": "Comment traiter une plaie profonde ou coupure importante ?","a3": "Arrêter immédiatement le saignement par compression directe avec linge stérile (5-10 min). Lever la plaie au-dessus du cœur. Appliquer pansement compressif. Appeler le SAMU si profus.","explain3": "La compression directe arrête le saignement. La surélévation réduit la pression artérielle locale. Un pansement compressif maintient la pression."},
  {"id": "70","type1": "VE","q1": "Comment vérifier la profondeur des sculptures d'un pneu ?","a1": "Utiliser le témoin d'usure (petit picot dans la rainure) ou une jauge. Le pneu est hors service si le témoin affleure ou dépasse 1,6 mm de profondeur.","explain1": "La profondeur légale minimale est 1,6 mm. En dessous, le drainage de l'eau est insuffisant, créant un risque d'aquaplaning maximal.","photo1": "temoin-usure-pneu.jpg","q2": "Quelles sont les conséquences d'une conduite avec des pneus usés ?","a2": "Perte d'adhérence, risque d'aquaplaning, distance de freinage allongée, infraction sanctionnée de 135€ et immobilisation possible du véhicule.","explain2": "Par pluie, un pneu usé sur sol mouillé entraîne une perte totale de contrôle. L'amende s'ajoute aux frais de remplacement.","q3": "Comment réagir face à une victime en convulsions fébriles ?","a3": "Allonger l'enfant sur le côté, libérer les voies aériennes, éviter de mettre des objets entre les dents, appeler le 15.","explain3": "Les convulsions fébriles sont dues à une montée rapide de température. Le positionnement latéral évite le risque d'étouffement."},
  {"id": "71","type1": "VI","q1": "Comment régler les rétroviseurs extérieurs depuis l'intérieur ?","a1": "Utiliser la manette ou l'écran tactile intérieur, actionner les flèches pour incliner chaque miroir. Voir l'arrière et légèrement le flanc du véhicule.","explain1": "Un bon réglage minimise les angles morts. Le rétroviseur doit montrer surtout l'arrière, pas trop le flanc du véhicule.","photo1": "commande-retroviseur-electrique.jpg","q2": "Pourquoi un angle mort mal réglé augmente le risque d'accident ?","a2": "Un conducteur ne voit pas une voiture dans l'angle mort en changement de voie. Cela provoque des accrochages ou des chocs latéraux graves.","explain2": "Un réglage optimal des rétroviseurs réduit les angles morts et permet d'anticiper le trafic latéral.","q3": "Comment secourir une victime souffrant d'une crise d'asthme ?","a3": "Asseoir la victime en position semi-assise, l'aider à prendre son inhalateur, ouvrir les fenêtres, rassurer. Appeler le 15 si aggravation.","explain3": "L'asthme crée une contraction des bronches. La position assise réduit la charge cardiaque et facilite la respiration."},
  {"id": "72","type1": "VE","q1": "Où trouver la valeur de pression de pneu préconisée ?","a1": "Sur l'étiquette collée à l'intérieur de la portière conducteur, le bas du montant de porte, ou dans le manuel du propriétaire. Jamais sur le pneu lui-même.","explain1": "Le flanc du pneu indique la pression maximale, pas la préconisée. La valeur d'utilisation figure dans le carnet d'entretien.","photo1": "etiquette-pression-pneu.jpg","q2": "Quel risque pose une pression de pneu incorrecte ?","a2": "Sous-gonflé : consommation élevée, usure rapide, risque d'échauffement. Surgonflé : rigidité, usure au centre, freinage réduit.","explain2": "La pression affecte la surface de contact, l'adhérence et la durée de vie du pneu. Une vérification mensuelle est obligatoire.","q3": "Quels sont les premiers gestes face à une douleur thoracique (infarctus) ?","a3": "Arrêter l'activité, asseoir ou allonger la victime, desserrer les vêtements, donner une aspiration si consciente, appeler le 15 immédiatement.","explain3": "L'infarctus est une urgence cardiaque. Chaque minute sans traitement aggrave les lésions du myocarde."},
  {"id": "73","type1": "VI","q1": "Comment tester le fonctionnement du frein de stationnement électrique ?","a1": "Appuyer sur le bouton ou la pédale, entendre le bruit de serrage. Vérifier l'indicateur au tableau de bord. Relâcher complètement avant de conduire.","explain1": "Un frein défaillant risque le déplacement du véhicule en stationnement. L'indicateur lumineux confirme l'engagement.","photo1": "frein-stationnement-electrique.jpg","q2": "Quel est le rôle du frein de stationnement en conduite normal ?","a2": "Immobiliser le véhicule à l'arrêt. En pente, il complète le frein moteur. Il ne doit jamais être actionné à l'aide de la boîte automatique seule.","explain2": "Le frein de stationnement évite un déplacement involontaire et prolonge la durée de vie des freins de service.","q3": "Comment agir face à une piqûre d'insecte avec réaction allergique ?","a3": "Éloigner de la zone, enlever le dard si visible avec un objet plat, appliquer du froid, surélever la zone. Appeler le 15 si urticaire/gonflement.","explain3": "Une allergie aux piqûres peut entraîner un choc anaphylactique. Le froid réduit l'inflammation locale."},
  {"id": "74","type1": "VE","q1": "Comment vérifier le fonctionnement des feux de stop ?","a1": "Appuyer sur la pédale de frein, observer l'illumination des feux arrière rouges. Vérifier des deux côtés (freinage normal et d'urgence).","explain1": "Les feux de stop avertissent les véhicules arrière. Une défaillance augmente le risque de choc par l'arrière.","photo1": "feux-stop-verification.jpg","q2": "Quels risques pose un feu de stop défaillant ?","a2": "Les véhicules arrière ne voient pas le freinage. Risque de choc par l'arrière, collision en chaîne, infraction de 135€.","explain2": "Les feux de stop sont une sécurité passive essentielle. Leur absence peut être fatale en freinage d'urgence.","q3": "Comment secourir une victime en cas de coup de chaleur ?","a3": "Mettre la victime à l'ombre, la déshabiller partiellement, appliquer de l'eau fraîche sur le corps, donner à boire si consciente, appeler le 15.","explain3": "Le coup de chaleur élève dangereusement la température interne. Le refroidissement rapide prévient les convulsions et l'arrêt cardiaque."},
  {"id": "75","type1": "VI","q1": "Comment vérifier le fonctionnement du voyant de portes ouvertes ?","a1": "Ouvrir et fermer chaque porte progressivement, observer le voyant au tableau de bord. Vérifier que le message disparaît quand toutes sont fermées.","explain1": "Un défaut d'étanchéité des portes augmente les appels d'air, les bruits et le bruit de vent. Le voyant signale une porte mal claquée.","photo1": "voyant-porte-ouverte.jpg","q2": "Pourquoi une porte mal fermée pose un risque routier ?","a2": "Risque d'ouverture intempestive en courbe, éjection de passagers, distraction du conducteur, infraction d'insécurité.","explain2": "Une porte qui s'ouvre en roulant expose les passagers et déporte les autres usagers.","q3": "Quels sont les signes d'un AVC et comment réagir ?","a3": "Mémo FAST : Face (visage asymétrique), Arm (bras qui tombe), Speech (parole incompréhensible), Time (appeler le 15 tout de suite).","explain3": "Chaque minute compte : 2 millions de neurones meurent par minute sans traitement. Aucune boisson, rester allongé."},
  {"id": "76","type1": "VE","q1": "Comment vérifier l'éclairage de la plaque arrière ?","a1": "Vérifier que les ampoules s'allument quand l'éclairage avant est activé. S'assurer que la plaque est bien lisible de 20 m. Nettoyer le verre si encrassé.","explain1": "L'éclairage de plaque est obligatoire pour l'identification du véhicule la nuit. Une plaque non lisible = infraction.","photo1": "eclairage-plaque-arriere.jpg","q2": "Quel risque pose une plaque arrière illisible la nuit ?","a2": "Impossibilité d'identifier le véhicule, problèmes lors d'un contrôle routier, infraction de 135€, impact sur l'assurance en cas d'accident.","explain2": "La plaque arrière permet l'identification légale du véhicule. Son éclairage est vérifiée lors du contrôle technique.","q3": "Comment réagir face à une victime gélée (gel/engelures) ?","a3": "Mettre à l'abri, réchauffer progressivement (jamais frottement), donner boisson chaude si consciente, enlever vêtements mouillés, appeler le 15.","explain3": "Le gel détruit les tissus cellulaires. Un réchauffement brutal amplifie les dégâts. Le repos et la réhydratation sont essentiels."},
  {"id": "77","type1": "VI","q1": "Comment régler la hauteur de la ceinture de sécurité ?","a1": "Placer le curseur sur l'ancrage vertical. La ceinture doit passer au-dessus de l'épaule, ne pas raser le cou. Tester la position en freinage.","explain1": "Une ceinture bien positionnée répartit les forces d'impact sur le sternum. Mal positionnée, elle blesse la gorge ou les côtes.","photo1": "reglage-ceinture-securite.jpg","q2": "Pourquoi régler la ceinture de sécurité est crucial pour les enfants ?","a2": "Une ceinture mal positionnée sur un enfant cause des blessures graves en cas de freinage. Un siège adapté à l'âge/poids est obligatoire.","explain2": "L'amortissement de la ceinture dépend de la surface de contact. Une mauvaise position crée des points de pression dangereux.","q3": "Comment secourir une victime d'accident de deux-roues avec casque ?","a3": "Ne pas retirer le casque sauf si arrêt cardiaque imminent. Tourner la victime en position latérale (si casque OK), maintenir la tête, appeler le 15.","explain3": "Le retrait du casque peut aggraver les blessures médullaires. La position latérale prévient l'étouffement par salive/sang."},
  {"id": "78","type1": "VE","q1": "Comment vérifier le fonctionnement des feux de recul ?","a1": "Mettre le véhicule au point mort ou en marche arrière, appuyer sur la pédale de frein, observer l'illumination des feux blancs arrière.","explain1": "Les feux de recul avertissent que le véhicule recule. Leur absence augmente le risque de choc avec piétons ou objets.","photo1": "feux-recul-verification.jpg","q2": "Quel risque pose une absence de feux de recul lors d'un stationnement ?","a2": "Invisibilité du recul pour les piétons, collision avec des véhicules ou des obstacles, responsabilité légale du conducteur.","explain2": "Les feux de recul sont une sécurité passive obligatoire. Leur défaillance compromet la visibilité arrière en basse luminosité.","q3": "Quels sont les gestes face à une entorse de la cheville ?","a3": "Arrêter l'activité, immobiliser le pied, appliquer du froid (glaçon), surélever, compresser légèrement. Appeler le 15 si gonflement sévère.","explain3": "Une entorse déchire les ligaments. Le froid réduit l'inflammation et l'immobilisation prévient l'aggravation."},
  {"id": "79","type1": "VI","q1": "Comment tester la caméra de recul et son écran d'affichage ?","a1": "Mettre en marche arrière, observer l'image sur l'écran. Vérifier les lignes de repère, la clarté et l'absence de résidu sur la lentille.","explain1": "La caméra de recul affiche les obstacles arrière. Une image floue ou bloquée augmente le risque de collision en marche arrière.","photo1": "camera-recul-test.jpg","q2": "Pourquoi la caméra de recul est-elle une aide à la sécurité importante ?","a2": "Elle élimine l'angle mort arrière, affiche les piétons et obstacles non visibles au rétroviseur, réduit les accidents de recul.","explain2": "La majorité des accidents de recul impliquent des enfants. La caméra améliore sensiblement la visibilité arrière.","q3": "Comment agir face à un traumatisme crânien ?","a3": "Mettre en position latérale, surveiller la conscience et la respiration, ne pas masser, appliquer un pansement léger, appeler le 15.","explain3": "Un traumatisme crânien peut causer un œdème cérébral. La surveillance et l'immobilisation de la tête sont essentielles."},
  {"id": "80","type1": "VE","q1": "Comment vérifier l'état des essuie-glaces arrière ?","a1": "Actionner le commutateur, observer le passage des balais sur la vitre. Vérifier l'absence de raies ou de zones non nettoyées. Changer si usés.","explain1": "Les essuie-glaces usés rayent la vitre et réduisent la visibilité arrière. Un mauvais nettoyage augmente les risques de choc par l'arrière.","photo1": "essuie-glace-arriere-verification.jpg","q2": "Quel risque pose des essuie-glaces arrière défaillants par temps de pluie ?","a2": "Visibilité arrière réduite, impossibilité de voir les véhicules qui approchent, risque de choc par l'arrière, infraction possible.","explain2": "Les essuie-glaces arrière complètent les rétroviseurs. Par pluie, leur absence compromet la visibilité arrière critique.","q3": "Comment secourir une victime souffrant d'une luxation de l'épaule ?","a3": "Immobiliser le bras en position confortable, appliquer du froid, faire un écharpe improvisée si possible, appeler le 15. Ne pas forcer la réduction.","explain3": "Une luxation désemboîte l'articulation. La réduction doit être faite par un professionnel pour éviter des lésions nerveuses."},
  {"id": "81","type1": "VI","q1": "Comment régler les appuie-têtes arrière depuis l'intérieur ?","a1": "Régler la hauteur de sorte que la tête soit alignée avec le sommet de l'appuie-tête, ni trop haut ni trop bas. Vérifier la stabilité.","explain1": "Un appuie-tête bien positionné réduit le risque de coup du lapin (hyperextension du cou). Sa hauteur doit être ajustée à chaque passager.","photo1": "appuie-tete-reglage.jpg","q2": "Pourquoi un appuie-tête mal réglé augmente les risques en cas de collision arrière ?","a2": "Un appuie-tête trop bas ou trop haut ne protège pas. Le cou subit une hyperextension, causant douleurs chroniques et lésions médullaires.","explain2": "Le coup du lapin entraîne des lésions cervicales durables. Un appuie-tête optimal répartit les forces d'impact.","q3": "Quels sont les gestes face à une plaie abdominale avec saignement ?","a3": "Allonger la victime, ne pas retirer l'objet s'il est coincé, compresser légèrement autour, maintenir le bassin immobile, appeler le 15.","explain3": "Une plaie abdominale peut atteindre les organes internes. L'immobilité et le panrage sans appuyer fort préviennent l'aggravation."},
  {"id": "82","type1": "VE","q1": "Comment vérifier le fonctionnement des commandes au volant (cruise control) ?","a1": "En roulant à vitesse stable, activer le cruise control, augmenter/diminuer la vitesse mémorisée, vérifier le maintien. Désactiver avec la pédale de frein.","explain1": "Le cruise control réduit la fatigue. Un défaut peut causer une accélération incontrôlée ou une perte de contrôle à haute vitesse.","photo1": "cruise-control-volant.jpg","q2": "Quel risque pose un cruise control défaillant ?","a2": "Accélération incontrôlée, impossibilité de freiner correctement, perte de contrôle du véhicule, accident grave à autoroute.","explain2": "Le cruise control doit être désactivable immédiatement par la pédale de frein. Un défaut engendre une situation critique.","q3": "Comment agir face à une victime ayant une plaie avec saignement de nez ?","a3": "Incliner légèrement la tête en avant, appuyer sur la narine, respirer par la bouche, appliquer du froid sur le front si saignement abondant.","explain3": "Un saignement de nez vient généralement du septum. L'appui sur la narine avec la tête penchée arrête le saignement en 10 minutes."},
  {"id": "83","type1": "VI","q1": "Comment tester le fonctionnement de la commande de rétroviseurs électriques ?","a1": "Avec le moteur en marche, actionner les boutons du sélecteur de rétroviseur. Chaque miroir doit se déplacer dans tous les sens sans blocage.","explain1": "Les rétroviseurs électriques permettent un ajustement précis sans quitter la place de conduite. Un moteur grippé réduit la manœuvre.","photo1": "commande-retroviseur-electrique-test.jpg","q2": "Pourquoi un rétroviseur électrique défaillant pose un problème de sécurité ?","a2": "Incapacité à ajuster la vision arrière, angles morts augmentés, risque accru lors des changements de voie, accident possible.","explain2": "Un rétroviseur bien ajusté élimine les angles morts critiques. Un défaut électrique force à s'arrêter pour régler manuellement.","q3": "Comment secourir une victime d'un accident de deux-roues sans casque ?","a3": "Appeler immédiatement le 15, placer la victime en position latérale si non-consciente, surveiller la respiration, appliquer premiers secours si compétent.","explain3": "L'absence de casque crée des traumatismes crâniens graves. L'immobilisation et la surveillance sont critiques en attendant l'ambulance."},
  {"id": "84","type1": "VE","q1": "Comment vérifier le joint du capot moteur ?","a1": "Ouvrir le capot, inspecter le joint en caoutchouc sur tout le périmètre. Chercher des fissures, des déchirures ou un joint mal assis. Fermer doucement.","explain1": "Un joint usé laisse l'eau s'infiltrer sous le capot, corrodant les composants électriques et moteur. Il doit être intact sur toute sa longueur.","photo1": "joint-capot-moteur.jpg","q2": "Quel risque pose un joint de capot dégradé ?","a2": "Infiltration d'eau lors de pluies fortes, corrosion des éléments électriques, court-circuit des relais, risque de panne moteur imprévue.","explain2": "L'eau qui s'infiltre sous le capot endommage les faisceaux électriques et les connecteurs. Une corrosion progressive augmente les dysfonctionnements.","q3": "Quels sont les premiers gestes face à une victime ensevelie partiellement ?","a3": "Vérifier la respiration, appeler les secours immédiatement, ne pas dégager brutalement, maintenir la mobilisation douce si possible.","explain3": "Une victime ensevelie peut avoir des blessures internes graves. Le dégagement brusque entraîne des hémorragies massives."},
  {"id": "85","type1": "VI","q1": "Comment tester l'affichage tête haute (si équipé) du véhicule ?","a1": "Démarrer le moteur, vérifier que l'image s'affiche sur le pare-brise. Régler la luminosité et la hauteur. Vérifier la lisibilité de jour et de nuit.","explain1": "L'affichage tête haute permet au conducteur de consulter les infos sans quitter la route. Un affichage défaillant crée une distraction supplémentaire.","photo1": "affichage-tete-haute.jpg","q2": "Pourquoi un affichage tête haute défaillant augmente les risques de distraction ?","a2": "Le conducteur baisse le regard vers le tableau de bord au lieu de le consulter sur le pare-brise, détournant son attention de la route.","explain2": "Un affichage en vision naturelle réduit le temps d'accommodation oculaire et améliore la sécurité routière.","q3": "Quels sont les signes d'une crise d'asthme et comment réagir ?","a3": "Respiration rapide et sifflante, oppression thoracique, panique. Asseoir en position assise, aider avec inhalateur, ouvrir les fenêtres, rassurer.","explain3": "L'asthme crée une constriction bronchique. La position assise réduit l'effort cardiaque et facilite la respiration."},
  {"id": "86","type1": "VE","q1": "Comment vérifier le bouchon de remplissage du carburant ?","a1": "Localiser le bouchon (souvent sur le côté arrière), vérifier qu'il dévisse sans résistance. S'assurer qu'il ferme bien et ne fuit pas. Remplacer si fissuré.","explain1": "Un bouchon défaillant laisse s'échapper les vapeurs d'essence, crée des odeurs, et expose à des risques d'inflammation en cas d'accident.","photo1": "bouchon-carburant.jpg","q2": "Quel risque pose un bouchon de carburant desserré ou défaillant ?","a2": "Odeur d'essence permanente, fuite de carburant, risque d'incendie en cas d'accident, exposition à des vapeurs toxiques.","explain2": "Le bouchon assure l'étanchéité du réservoir. Un défaut crée une source de feu potentielle en cas de choc.","q3": "Quels sont les premiers gestes face à une douleur thoracique (possible infarctus) ?","a3": "Arrêter l'activité, asseoir ou allonger la victime, desserrer vêtements, donner aspiration si consciente, appeler le 15 immédiatement.","explain3": "L'infarctus détruit le muscle cardiaque. Chaque minute sans traitement spécialisé augmente les risques de décès."},
  {"id": "87","type1": "VI","q1": "Comment tester le fonctionnement du chauffage de siège ?","a1": "Appuyer sur le bouton ou le curseur du chauffage, sentir progressivement la chaleur. Vérifier les 3 niveaux et l'absence de surchauffe. Laisser refroidir.","explain1": "Le chauffage de siège consomme beaucoup d'électricité. Un défaut peut surcharger le circuit électrique ou créer une brûlure sur peau sensible.","photo1": "chauffage-siege.jpg","q2": "Pourquoi un chauffage de siège défaillant (toujours allumé) pose un problème ?","a2": "Épuisement de la batterie, surcharge du circuit électrique, risque d'incendie si court-circuit, brûlure de la peau en utilisation prolongée.","explain2": "Le chauffage de siège doit être contrôlable et se couper automatiquement. Un défaut crée une source de chaleur incontrôlée.","q3": "Comment secourir une victime souffrant d'une douleur thoracique (angine de poitrine) ?","a3": "Asseoir en position semi-assise, aider à prendre son médicament (nitrate) si disponible, respirer profondément, appeler le 15 si douleur persiste.","explain3": "L'angine est une ischémie cardiaque réversible. L'arrêt et la nitrate réduisent la demande cardiaque et soulagent la douleur."},
  {"id": "88","type1": "VE","q1": "Comment vérifier l'état des pare-chocs ?","a1": "Inspecter avant et arrière pour fissures, déformations, couleur inégale, éléments manquants ou mal fixés. Appuyer légèrement pour vérifier la solidité.","explain1": "Les pare-chocs absorbent les chocs à basse vitesse. Un pare-choc endommagé expose les éléments mécaniques et électriques aux intempéries.","photo1": "etat-pare-chocs.jpg","q2": "Quel risque pose un pare-chocs détérioré lors d'un petit choc ?","a2": "Dommages accrus aux éléments de structure, rayure du cadre, dégâts à capteurs et câbles électriques, réparations onéreuses, perte de sécurité passive.","explain2": "Un pare-chocs endommagé transmet les forces directement à la structure. Les réparations augmentent rapidement de coût.","q3": "Quels sont les premiers gestes face à une luxation d'épaule ?","a3": "Immobiliser le bras en position confortable (écharpe improvisée), appliquer du froid, donner antalgique si consciente, appeler le 15 sans délai.","explain3": "Une luxation désemboîte l'articulation glénohumérale. La réduction nécessite une radiographie et doit être faite par un professionnel."},
  {"id": "89","type1": "VI","q1": "Comment vérifier la propreté et la fonction des rétroviseurs intérieurs et extérieurs ?","a1": "Nettoyer les miroirs avec un chiffon doux. Vérifier l'absence de buée persistante dans le rétroviseur intérieur. Ajuster pour une vue optimale.","explain1": "Des rétroviseurs sales ou embrumés réduisent drastiquement la visibilité arrière. La buée persistante indique un joint défaillant.","photo1": "retroviseur-nettoyage.jpg","q2": "Pourquoi des rétroviseurs sales augmentent les risques d'accident ?","a2": "Visibilité arrière réduite, angles morts augmentés, impossibilité de voir les véhicules proches, risque de choc lors des changements de voie.","explain2": "La visibilité arrière est essentielle à chaque manœuvre. Des rétroviseurs encrassés augmentent les risques de collision.","q3": "Comment réagir face à une victime victime d'une convulsion fébrile chez l'enfant ?","a3": "Allonger l'enfant sur le côté, libérer les voies aériennes, noter la durée, ne pas forcer, appeler le 15 si convulsion > 5 min.","explain3": "Les convulsions fébriles sont dues à une montée rapide de la température. Le positionnement latéral prévient l'asphyxie."},
  {"id": "90","type1": "VE","q1": "Comment vérifier la propreté des rétroviseurs extérieurs ?","a1": "Nettoyer les miroirs avec un chiffon doux et de l'eau savonneuse. Vérifier l'absence de rayures ou d'éclaboussures. Vérifier la stabilité du support.","explain1": "Des rétroviseurs encrassés (boue, pluie, neige) réduisent drastiquement la visibilité arrière. Le nettoyage régulier est essentiel en hiver.","photo1": "retroviseur-exterieur-propre.jpg","q2": "Quel risque pose des rétroviseurs extérieurs sales en condition météo difficile ?","a2": "Visibilité arrière quasi nulle en pluie/neige, impossibilité de voir les véhicules proches, risque accru de collision, choc par l'arrière.","explain2": "Les rétroviseurs extérieurs sont la première ligne de visibilité arrière. Leur encrassement aggrave les angles morts critiques.","q3": "Quels sont les premiers gestes face à une victime souffrant d'une allergie (choc anaphylactique) ?","a3": "Appeler immédiatement le 15, allonger la victime, surélever les jambes, aider à utiliser un auto-injecteur d'épinéphrine si disponible, surveiller.","explain3": "Le choc anaphylactique peut être fatal. L'épinéphrine est le seul traitement immédiat efficace pour reverser les symptômes."},
  {"id": "91","type1": "VI","q1": "Comment tester la commande d'ouverture du coffre depuis l'habitacle ?","a1": "Appuyer sur le bouton ou la manette d'ouverture du coffre. Vérifier que le coffre s'ouvre complètement. Fermer doucement en testant la fermeture.","explain1": "L'ouverture électrique du coffre facilite le chargement. Un défaut d'ouverture laisse le conducteur sans accès au coffre en urgence.","photo1": "commande-coffre.jpg","q2": "Pourquoi l'impossibilité d'ouvrir le coffre crée un problème de sécurité ?","a2": "Accès impossible aux dispositifs de sécurité (triangle, gilet), impossibilité de remplacer une roue, dépannage difficile en urgence.","explain2": "Le coffre doit être accessible pour les équipements de sécurité obligatoires. Un blocage électrique nécessite dépannage urgent.","q3": "Quels sont les signes d'une insolation (coup de chaleur) et comment réagir ?","a3": "Mal de tête, étourdissements, peau rouge/sèche, possible perte de conscience. Mettre à l'ombre, refroidir le corps progressivement, donner à boire.","explain3": "L'insolation élève dangereusement la température interne. Le refroidissement rapide prévient les complications graves."},
  {"id": "92","type1": "VE","q1": "Comment vérifier la présence et l'état de l'antenne et des équipements de toit ?","a1": "Inspecter l'antenne pour déformation, rupture ou mauvaise fixation. Vérifier le support et l'absence de rouille. S'assurer que tout élément est bien fixé.","explain1": "Une antenne endommagée crée des bruits parasites à la radio. Une mauvaise fixation risque la perte d'équipement en roulant.","photo1": "antenne-verification.jpg","q2": "Quel risque pose une antenne mal fixée ou endommagée ?","a2": "Bruits parasites de réception radio, perte d'antenne en roulant, projectile dangereux sur la route, réception nulle de services d'urgence.","explain2": "Une antenne endommagée compromet les communications radio (musique, GPS, secours). Une mauvaise fixation crée un projectile.","q3": "Comment secourir une victime souffrant d'une contusion ou trauma du genou ?","a3": "Immobiliser le genou en position légèrement fléchie, appliquer du froid, surélever la jambe, compresser légèrement. Appeler le 15 si gonflement sévère.","explain3": "Une contusion du genou peut cacher une fracture ou une lésion ligamentaire. L'immobilité et le froid réduisent l'inflammation."},
  {"id": "93","type1": "VI","q1": "Comment tester l'avertisseur de fatigue (si équipé) du véhicule ?","a1": "Rouler à 100 km/h environ, reproduire des écarts involontaires (tirettes de route), vérifier que l'avertisseur se déclenche (sonnerie ou vibration).","explain1": "L'avertisseur de fatigue détecte les écarts involontaires de trajectoire. Un défaut réduit l'alerte sur fatigue du conducteur.","photo1": "avertisseur-fatigue.jpg","q2": "Pourquoi un avertisseur de fatigue défaillant diminue la sécurité ?","a2": "Absence d'alerte sur la fatigue, risque augmenté de perte de conscience, sommeille au volant sans signal, accident grave non prévenu.","explain2": "La fatigue cause 30% des accidents autoroute. Un avertisseur fonctionnel crée une prise de conscience critique.","q3": "Comment agir face à une victime souffrant d'une gelure (extrémité gelée) ?","a3": "Mettre à l'abri, réchauffer progressivement (jamais frottement), donner boisson chaude si consciente, enlever vêtements mouillés, appeler le 15.","explain3": "Le gel détruit les cellules. Un réchauffement brutal (feu) amplifie les dégâts. Le réchauffement passif est la seule technique acceptée."},
  {"id": "94","type1": "VE","q1": "Comment vérifier le niveau de carburant visuellement ?","a1": "Ouvrir le bouchon du réservoir (ou le contrôler électroniquement). Observer la quantité approximative de carburant dans le réservoir. Ne jamais laisser le niveau baisser trop bas.","explain1": "Un réservoir vide risque une panne moteur sur autoroute. Le niveau bas peut endommager la pompe à carburant par manque de refroidissement.","photo1": "niveau-carburant.jpg","q2": "Quel risque pose la conduite avec un réservoir presque vide ?","a2": "Panne moteur imprévue, endommagement de la pompe à carburant, blocage sur l'autoroute, risque d'accident en urgence.","explain2": "La pompe à carburant se refroidit dans l'essence. Un réservoir vide la surchauffe et réduit sa durée de vie.","q3": "Quels sont les premiers gestes face à une victime atteinte d'un traumatisme crânien ?","a3": "Allonger la victime, placer en position latérale si inconsciente, immobiliser la tête, surveiller la respiration, appeler le 15 immédiatement.","explain3": "Un traumatisme crânien peut causer un saignement interne. L'immobilisation et la surveillance sont vitales en attente de soins."},
  {"id": "95","type1": "VI","q1": "Comment vérifier la ceinture de sécurité (fonction et usure) ?","a1": "Tirer fortement sur chaque ceinture, vérifier qu'elle bloque sans se détendre. Inspecter le tissu pour déchirures ou effilochage. Vérifier le mécanisme de fermeture.","explain1": "Une ceinture usée ou défaillante ne retient pas la victime en cas de choc. Son usure réduit son efficacité lors d'un freinage d'urgence.","photo1": "ceinture-securite-test.jpg","q2": "Pourquoi une ceinture de sécurité défaillante augmente dramatiquement les risques d'accident ?","a2": "Absence de retenue en cas de freinage brutal ou de choc, projection du passager contre le pare-brise, décès ou blessures graves.","explain2": "La ceinture répartit les forces d'impact sur une zone large du corps. Son efficacité dépend de son état et de sa tension.","q3": "Comment réagir face à une victime avec une plaie avec saignement intense au bras ?","a3": "Comprimer la plaie avec un linge propre, maintenir la pression 10-15 min, surélever le bras au-dessus du cœur, faire un pansement, appeler le 15.","explain3": "L'hémorragie externe met en danger la vie. La compression prolongée et l'élévation réduisent la perte sanguine."},
  {"id": "96","type1": "VE","q1": "Comment vérifier l'état et le serrage du joint du coffre arrière ?","a1": "Ouvrir le coffre, inspecter le joint en caoutchouc sur tout le périmètre. Chercher des fissures, des déchirures. Appuyer pour vérifier la compression.","explain1": "Un joint de coffre usé laisse l'eau s'infiltrer, causant corrosion des équipements électriques, pourrissement de la moquette et odeurs.","photo1": "joint-coffre.jpg","q2": "Quel risque pose un joint de coffre dégradé par temps de pluie ?","a2": "Infiltration d'eau massif, corrosion des commandes électriques, panne des feux arrière, dégâts de fret à l'intérieur du coffre.","explain2": "Le joint de coffre assure l'étanchéité. Un défaut crée une zone d'eau stagnante qui corrode et dégrade progressivement les équipements.","q3": "Comment secourir une victime victime d'une brûlure thermique (contact chaleur) ?","a3": "Arroser à l'eau froide (15°C) 15-20 min, enlever vêtements non adhérents, éviter la glace, couvrir légèrement, appeler le 15.","explain3": "L'eau froide arrête la progression thermique. L'immersion prolongée prévient les séquelles. Ne jamais utiliser de pansements gras."},
  {"id": "97","type1": "VI","q1": "Comment vérifier la stabilité et le serrage des appuie-bras et accoudoirs ?","a1": "Tirer fermement sur chaque appuie-bras, vérifier qu'il ne bouge pas ou ne se plie. S'assurer que les vis de fixation ne sont pas desserrées.","explain1": "Un appuie-bras mal fixé peut se casser en usage normal, créant une blessure ou une distraction lors de la conduite.","photo1": "appuie-bras-verification.jpg","q2": "Pourquoi un appuie-bras défaillant pose un problème de confort et sécurité ?","a2": "Perte de support ergonomique, fatigue musculaire accrue du conducteur, distraction en cas de rupture ou bruit de frottement.","explain2": "Un appuie-bras bien fixé réduit la fatigue des membres et améliore le confort de long trajet.","q3": "Quels sont les signes d'une douleur articulaire (arthrite/arthrose) et comment réagir ?","a3": "Gonflement, raideur, douleur à l'effort. Appliquer du froid 15 min, immobiliser, donner anti-inflammatoire si consciente, conseiller repos prolongé.","explain3": "L'arthrite est une inflammation articulaire chronique. Le repos et les anti-inflammatoires réduisent les symptômes."},
  {"id": "98","type1": "VE","q1": "Comment vérifier l'état général des poignées de portes (intérieures et extérieures) ?","a1": "Tirer fortement sur chaque poignée, vérifier qu'elle ne bouge pas. Vérifier l'absence de corrosion, de rayures profondes ou de casse du plastique.","explain1": "Une poignée cassée empêche l'ouverture de la porte en cas d'urgence. Une poignée interne défaillante laisse la personne piégée.","photo1": "poignee-porte-verification.jpg","q2": "Quel risque pose une poignée de porte intérieure défaillante ?","a2": "Impossibilité d'ouvrir la porte de l'intérieur en cas d'urgence, piégeage du passager, évacuation impossible en accident grave.","explain2": "La poignée interne est un dispositif de sécurité essentiel. Son défaut crée un risque de piégeage fatal.","q3": "Comment agir face à une victime atteinte d'une perte de conscience ?","a3": "Allonger sur le dos, basculer la tête en arrière pour dégager les voies aériennes, tourner en position latérale si position possible, appeler le 15.","explain3": "Une personne inconsciente peut s'étouffer. La position latérale prévient l'asphyxie et permet la drainage des sécrétions."},
  {"id": "99","type1": "VI","q1": "Comment vérifier le mécanisme de fermeture des ceintures de sécurité pour enfants ?","a1": "Boucler la ceinture, vérifier qu'elle s'enclenche bien. Tirer fermement sur la sangle, vérifier qu'elle ne déraille pas. Déboucler en appuyant sur le bouton.","explain1": "Un mécanisme défaillant ne retient pas l'enfant en cas de choc. La sécurité de l'enfant dépend du bon verrouillage de la ceinture.","photo1": "mecanisme-ceinture-enfant.jpg","q2": "Pourquoi un mécanisme de ceinture pour enfant défaillant est critique ?","a2": "Absence de retenue en cas de choc, risque d'éjection, blessures graves ou fatales, violation de la loi de sécurité routière.","explain2": "La ceinture de l'enfant est sa seule retenue. Un défaut du mécanisme le laisse sans protection lors d'un accident.","q3": "Quels sont les premiers gestes face à une victime en arrêt cardio-respiratoire ?","a3": "Appeler le 15 (ou 112) immédiatement, commencer RCP (30 compressions thoraciques, 2 insufflations) si formé. Placer le défibrillateur si disponible.","explain3": "L'arrêt cardiaque est une urgence extrême. La RCP maintient la circulation sanguine jusqu'à l'arrivée de l'ambulance. Chaque minute compte."}
]
// Helper pour récupérer un scénario par ID
export function getScenarioById(id) {
  return SCENARIOS.find(s => s.id === String(id).padStart(2, '0')) || null
}
